/* ============================================
 * VFS 核心逻辑：文件系统注册表与探测机制
 * ============================================
 * 参考仓库：T202510589995148-2209/crates/axfs-ng-vfs/src/fs.rs
 * 参考仓库：T202510589995148-2209/core/src/vfs/mod.rs
 * 开源协议：MIT (axfs-ng-vfs) + MPL-2.0 (arceos)
 * 架构映射：Rust FilesystemOps<M> trait 体系 → C 函数指针表
 * 
 * 探测流程：
 *   1. 读取磁盘扇区 0
 *   2. 遍历注册的文件系统类型链表
 *   3. 调用各 fs_type->probe(sector0)
 *   4. 第一个返回 1 的类型即为匹配成功
 *   5. 无匹配则输出 magic 信息后 panic
 * ============================================ */

/* 注册表头指针 */
static struct vfs_fs_type *vfs_fs_list = NULL;

/* 当前激活的文件系统类型 */
struct vfs_fs_type *vfs_active_fs = NULL;

/* 根文件系统超级块 */
struct vfs_super_block vfs_root_sb;

/* 全局锁（保护注册表链表） */
static spinlock_t vfs_lock;

/* ============================================
 * VFS 初始化
 * ============================================ */
void vfs_init(void)
{
    spinlock_init(&vfs_lock, "vfs_lock");
    vfs_fs_list = NULL;
    vfs_active_fs = NULL;
    vfs_root_sb.fs_type = NULL;
    vfs_root_sb.s_op = NULL;
    vfs_root_sb.fs_private = NULL;
    vfs_root_sb.block_size = 512;
    vfs_root_sb.sector_size = 512;
    vfs_root_sb.s_root = NULL;
    memset(vfs_root_sb.s_name, 0, sizeof(vfs_root_sb.s_name));
}

/* ============================================
 * 注册文件系统类型
 * ============================================ */
void vfs_register_fs(struct vfs_fs_type *fs)
{
    if (fs == NULL)
        return;

    spinlock_acquire(&vfs_lock);
    fs->next = vfs_fs_list;
    vfs_fs_list = fs;
    spinlock_release(&vfs_lock);

    printf("[VFS] Registered filesystem: %s\n", fs->name);
}

/* ============================================
 * 文件系统探测引擎
 * 
 * 遍历注册表，调用各类型 probe 函数，
 * 返回第一个匹配的文件系统类型指针，
 * 无匹配返回 NULL。
 * ============================================ */
struct vfs_fs_type *vfs_probe_filesystem(buf_t *sector0)
{
    struct vfs_fs_type *p;
    struct vfs_fs_type *matched_fs = NULL;

    if (sector0 == NULL)
        return NULL;

    printf("[VFS] Probing filesystem type...\n");

    /* 在单 CPU 环境下，注册完成后链表不再变化。
     * 为避免 probe 内部可能睡眠（如 buf_read → virtio_disk_rw → proc_sleep）
     * 导致 sched locks panic，释放 vfs_lock 后再调用 probe。
     */
    spinlock_acquire(&vfs_lock);
    p = vfs_fs_list;
    spinlock_release(&vfs_lock);

    while (p != NULL) {
        if (p->probe(sector0)) {
            matched_fs = p;
            break;
        }
        p = p->next;
    }

    if (matched_fs) {
        printf("[VFS] Matched filesystem: %s\n", matched_fs->name);
    }

    return matched_fs;
}

/* ============================================
 * EXT4 探测函数
 * 
 * 无分区表 EXT4 镜像：
 *   superblock 位于扇区0偏移 1024 字节处。
 *   检查 s_magic 字段（偏移 0x38）是否等于 0xEF53。
 * ============================================ */
static int ext4_probe(buf_t *sector0)
{
    /* sector0 是 512 字节缓冲区，但 superblock 从偏移 1024 开始，
     * 这意味着 superblock 跨越了扇区 0 和扇区 1。
     * 1024 = 2 * 512，所以 s_magic 位于扇区2（sector index 2）
     * 的偏移 (1024 + 0x38) % 512 = 0x38 处。
     * 
     * 实际上，对于无分区表 EXT4：
     *   扇区 0: 0~511   (boot sector / padding)
     *   扇区 1: 512~1023 (padding)
     *   扇区 2: 1024~1535 (superblock starts at 1024)
     * 
     * 因此 s_magic (1024 + 0x38 = 1080 = 2*512 + 56)
     * 位于扇区 2 的偏移 56 (0x38) 处。
     */
    buf_t *sb_buf = buf_read(2);
    if (sb_buf == NULL)
        return 0;

    /* 注意：这里假设 buf_read(2) 返回的缓冲区起始就是扇区2的开头。
     * superblock 在扇区2内的偏移 = EXT4_SUPER_OFFSET % 512 = 0
     * 所以 sb_buf->data + 0 就是 struct ext4_super_block 的起点。
     * s_magic 在结构体中的偏移是 0x38。
     */
    struct ext4_super_block *sb = (struct ext4_super_block *)(sb_buf->data);
    uint16 magic = sb->s_magic;

    buf_release(sb_buf);

    printf("[VFS] Trying ext4: magic = 0x%x (expected 0x%x)\n",
           (uint32)magic, (uint32)EXT4_SUPER_MAGIC);

    if (magic == EXT4_SUPER_MAGIC)
        return 1;

    return 0;
}

/* ============================================
 * FAT32 探测函数
 * 
 * 检查 BPB 的 bytes_per_sector 是否为 512，
 * 且 fat_count > 0 作为基本 sanity check。
 * ============================================ */
static int fat32_probe(buf_t *sector0)
{
    struct fat32_bpb *bpb = (struct fat32_bpb *)sector0->data;
    uint16 bps = bpb->bytes_per_sector;
    uint8  fc  = bpb->fat_count;

    printf("[VFS] Trying fat32: bytes_per_sector=%d, fat_count=%d\n", bps, fc);

    if (bps == FAT32_SECTOR_SIZE && fc > 0 && fc <= 2)
        return 1;

    return 0;
}

/* ============================================
 * FAT32 mount wrapper
 * 
 * 将原有的 fat32_init() 包装为 VFS mount 回调，
 * 消除 fs.c 中的硬编码分支。
 * ============================================ */
static int fat32_mount_wrapper(struct vfs_super_block *sb)
{
    fat32_init();
    sb->fs_private = &fat_info;
    sb->block_size = FAT32_SECTOR_SIZE;
    sb->sector_size = FAT32_SECTOR_SIZE;
    printf("[VFS] FAT32 filesystem mounted successfully.\n");
    return 0;
}

/* ============================================
 * 预定义的文件系统类型实例
 * ============================================ */
static struct vfs_fs_type fat32_fs_type = {
    .name   = "fat32",
    .probe  = fat32_probe,
    .mount  = fat32_mount_wrapper,
    .next   = NULL
};

static struct vfs_fs_type ext4_fs_type = {
    .name   = "ext4",
    .probe  = ext4_probe,
    .mount  = ext4_mount,
    .next   = NULL
};

/* ============================================
 * 注册所有内置文件系统类型
 * 在 vfs_init 之后由 fs_init 调用
 * ============================================ */
void vfs_register_builtin_fs(void)
{
    vfs_register_fs(&fat32_fs_type);
    vfs_register_fs(&ext4_fs_type);
}

/* ============================================
 * 获取 FAT32 文件系统类型指针
 * 供 fat32.c 设置 mount 回调
 * ============================================ */
struct vfs_fs_type *vfs_get_fat32_type(void)
{
    return &fat32_fs_type;
}

