/* 挂载私有数据 */
struct ext4_mount_data {
    struct ext4_blockdev_glue glue;
    struct ext4_super_block  *sb;        /* kmalloc 分配的超级块副本 */
    struct ext4_group_desc   *gdt;       /* kmalloc 分配的 GDT 副本 */
    uint32 block_size;
    uint32 inode_size;
    uint32 blocks_per_group;
    uint32 inodes_per_group;
    uint32 num_groups;
    uint32 desc_size;       /* 块组描述符大小（32 或 64） */
};

/* 全局挂载数据（单文件系统，无需复杂管理） */
static struct ext4_mount_data *ext4_md = NULL;

enum {
    EXT4_INODE_CACHE_SIZE = 128,
    EXT4_LOOKUP_CACHE_SIZE = 128,
    EXT4_DIR_BLOCK_CACHE_SIZE = 16,
    EXT4_LOOKUP_NAME_MAX = 256,
};

struct ext4_inode_cache_entry {
    bool valid;
    uint32 inode_no;
    struct ext4_inode inode;
};

struct ext4_lookup_cache_entry {
    bool valid;
    uint32 parent_ino;
    char name[EXT4_LOOKUP_NAME_MAX];
    uint32 child_ino;
    uint8 file_type;
};

struct ext4_dir_block_cache_entry {
    bool valid;
    uint32 dir_ino;
    uint32 logical_block;
    uint64 physical_block;
    uint8 data[EXT4_MAX_BLOCK_SIZE];
};

static struct ext4_inode_cache_entry ext4_inode_cache[EXT4_INODE_CACHE_SIZE];
static struct ext4_lookup_cache_entry ext4_lookup_cache[EXT4_LOOKUP_CACHE_SIZE];
static struct ext4_dir_block_cache_entry ext4_dir_block_cache[EXT4_DIR_BLOCK_CACHE_SIZE];

enum {
    EXT4_BLOCK_MAPPED = 0,
    EXT4_BLOCK_ERROR = -1,
    EXT4_BLOCK_HOLE = -2,
};

/* VFS 操作表前向声明 */
static struct vfs_file_operations ext4_file_ops;
static struct vfs_inode_operations ext4_inode_ops;
static int ext4_read_block(void *buf, uint64 blk_id);
static uint64 ext4_get_data_block(struct ext4_inode *inode, uint32 n);

/* ---------- 静态辅助函数 ---------- */

static inline uint64 ext4_bg_inode_table(struct ext4_group_desc *gd)
{
    return (uint64)gd->bg_inode_table_lo;
}

static void ext4_cache_reset(void)
{
    memset(ext4_inode_cache, 0, sizeof(ext4_inode_cache));
    memset(ext4_lookup_cache, 0, sizeof(ext4_lookup_cache));
    memset(ext4_dir_block_cache, 0, sizeof(ext4_dir_block_cache));
}

static uint32 ext4_name_hash(const char *name)
{
    uint32 hash = 2166136261U;

    if (name == NULL)
        return 0;
    while (*name != '\0') {
        hash ^= (uint8)*name;
        hash *= 16777619U;
        name++;
    }
    return hash;
}

static int ext4_inode_cache_get(uint32 inode_no, struct ext4_inode *out)
{
    struct ext4_inode_cache_entry *entry;

    if (inode_no == 0 || out == NULL)
        return 0;
    entry = &ext4_inode_cache[inode_no % EXT4_INODE_CACHE_SIZE];
    if (!entry->valid || entry->inode_no != inode_no)
        return 0;
    memmove(out, &entry->inode, sizeof(*out));
    return 1;
}

static void ext4_inode_cache_put(uint32 inode_no, const struct ext4_inode *inode)
{
    struct ext4_inode_cache_entry *entry;

    if (inode_no == 0 || inode == NULL)
        return;
    entry = &ext4_inode_cache[inode_no % EXT4_INODE_CACHE_SIZE];
    entry->valid = true;
    entry->inode_no = inode_no;
    memmove(&entry->inode, inode, sizeof(entry->inode));
}

static int ext4_lookup_cache_get(uint32 parent_ino, const char *name,
                                 uint32 *out_ino, uint8 *out_file_type)
{
    struct ext4_lookup_cache_entry *entry;

    if (parent_ino == 0 || name == NULL || out_ino == NULL ||
        out_file_type == NULL)
        return 0;
    entry = &ext4_lookup_cache[
        (parent_ino ^ ext4_name_hash(name)) % EXT4_LOOKUP_CACHE_SIZE];
    if (!entry->valid || entry->parent_ino != parent_ino ||
        strcmp(entry->name, name) != 0)
        return 0;
    *out_ino = entry->child_ino;
    *out_file_type = entry->file_type;
    return 1;
}

static void ext4_lookup_cache_put(uint32 parent_ino, const char *name,
                                  uint32 child_ino, uint8 file_type)
{
    struct ext4_lookup_cache_entry *entry;

    if (parent_ino == 0 || child_ino == 0 || name == NULL ||
        strlen(name) >= EXT4_LOOKUP_NAME_MAX)
        return;
    entry = &ext4_lookup_cache[
        (parent_ino ^ ext4_name_hash(name)) % EXT4_LOOKUP_CACHE_SIZE];
    entry->valid = true;
    entry->parent_ino = parent_ino;
    entry->child_ino = child_ino;
    entry->file_type = file_type;
    strlcpy(entry->name, name, sizeof(entry->name));
}

static int ext4_dir_block_cache_get(uint32 dir_ino, struct ext4_inode *dir_inode,
                                    uint32 logical_block, void **out_block)
{
    struct ext4_dir_block_cache_entry *entry;
    uint64 physical_block;

    if (ext4_md == NULL || dir_ino == 0 || dir_inode == NULL ||
        out_block == NULL || ext4_md->block_size > EXT4_MAX_BLOCK_SIZE)
        return -1;

    entry = &ext4_dir_block_cache[
        (dir_ino ^ logical_block) % EXT4_DIR_BLOCK_CACHE_SIZE];
    if (entry->valid && entry->dir_ino == dir_ino &&
        entry->logical_block == logical_block) {
        *out_block = entry->data;
        return 1;
    }

    physical_block = ext4_get_data_block(dir_inode, logical_block);
    if (physical_block == 0)
        return 0;
    entry->valid = false;
    if (ext4_read_block(entry->data, physical_block) != 0)
        return -1;

    entry->valid = true;
    entry->dir_ino = dir_ino;
    entry->logical_block = logical_block;
    entry->physical_block = physical_block;
    *out_block = entry->data;
    return 1;
}

/* 通过粘合层读取一个逻辑块 */
static int ext4_read_block(void *buf, uint64 blk_id)
{
    if (ext4_md == NULL || buf == NULL)
        return -1;
    return ext4_glue_read_block(&ext4_md->glue, buf, blk_id);
}

/* 读取 Inode N（inode 号从 1 开始） */
static int ext4_read_inode(struct ext4_inode *inode_out, uint32 inode_no)
{
    if (ext4_md == NULL || inode_out == NULL || inode_no == 0)
        return -1;
    if (ext4_inode_cache_get(inode_no, inode_out))
        return 0;

    uint32 inodes_per_group = ext4_md->inodes_per_group;
    uint32 group_id = (inode_no - 1) / inodes_per_group;
    uint32 index_in_group = (inode_no - 1) % inodes_per_group;

    if (group_id >= ext4_md->num_groups) {
        printf("[EXT4] read_inode: inode %d out of range\n", inode_no);
        return -1;
    }

    struct ext4_group_desc *gd = &ext4_md->gdt[group_id];
    uint64 inode_table_blk = ext4_bg_inode_table(gd);

    /* Inode 在 inode 表中的字节偏移 */
    uint64 inode_offset = (uint64)index_in_group * ext4_md->inode_size;
    uint32 blk_in_table = inode_offset / ext4_md->block_size;
    uint32 off_in_blk = inode_offset % ext4_md->block_size;

    uint64 target_blk = inode_table_blk + blk_in_table;

    /* 分配临时块缓冲区 */
    void *blk_buf = kmalloc(ext4_md->block_size);
    if (blk_buf == NULL) {
        printf("[EXT4] read_inode: kmalloc failed for block buffer\n");
        return -1;
    }

    int ret = ext4_read_block(blk_buf, target_blk);
    if (ret != 0) {
        printf("[EXT4] read_inode: failed to read block %d\n", (uint32)target_blk);
        kfree(blk_buf);
        return -1;
    }

    memmove(inode_out, (uint8 *)blk_buf + off_in_blk, sizeof(struct ext4_inode));
    kfree(blk_buf);
    ext4_inode_cache_put(inode_no, inode_out);
    return 0;
}

