// 物理页链表节点数据结构
typedef struct page_node {
    struct page_node* next;
} page_node_t;

// 物理页链表
typedef struct alloc_region {
    uint64 begin; // 分配区起始地址
    uint64 end;   // 分配区结束地址
    spinlock_t lock; // 分配区自旋锁(保护链表操作)
    uint32 allocable; // 可分配页数
    page_node_t* list_head; // 物理页链表头节点
} alloc_region_t;

// 内核和用户可分配的物理页分开
static alloc_region_t kern_region, user_region;

#define KERN_MIN_PAGES 1024 // 内核可分配空间至少占1024个pages
#define KERN_PAGE_DIVISOR 16
#define PMEM_REF_MAX_PAGES ((1024UL * 1024UL * 1024UL) / PGSIZE)

static uint16 page_refs[PMEM_REF_MAX_PAGES];
static uint64 page_ref_base;
static uint64 page_ref_pages;

static void page_ref_init(uint64 begin, uint64 end)
{
    uint64 pages;

    if(end <= begin)
        panic("pmem_init: invalid ref range");

    pages = (end - begin) / PGSIZE;
    if(pages > PMEM_REF_MAX_PAGES)
        panic("pmem_init: ref table too small");

    page_ref_base = begin;
    page_ref_pages = pages;
    memset(page_refs, 0, sizeof(page_refs));
}

static int page_ref_index(uint64 page)
{
    uint64 idx;

    if(page_ref_pages == 0)
        panic("page_ref_index: not initialized");

    if((page % PGSIZE) != 0 || page < page_ref_base)
        panic("page_ref_index: invalid page");

    idx = (page - page_ref_base) / PGSIZE;
    if(idx >= page_ref_pages)
        panic("page_ref_index: out of range");

    return (int)idx;
}

// Helper function to initialize a region
static void region_init(alloc_region_t* region, char* name, uint64 begin, uint64 end) {
    spinlock_init(&region->lock, name);
    region->begin = ALIGN_UP(begin, PGSIZE);
    region->end = ALIGN_DOWN(end, PGSIZE);
    region->list_head = NULL;
    region->allocable = 0;

    for (uint64 p = region->begin; p + PGSIZE <= region->end; p += PGSIZE) {
        page_refs[page_ref_index(p)] = 1;
        pmem_free(p, (region == &kern_region));
    }
}

// 物理内存初始化
void  pmem_init(void)
{
    uint64 alloc_begin = ALIGN_UP((uint64)ALLOC_BEGIN, PGSIZE);
    uint64 alloc_end = ALIGN_DOWN((uint64)ALLOC_END, PGSIZE);
    uint64 total_pages = (alloc_end - alloc_begin) / PGSIZE;
    uint64 kern_pages = total_pages / KERN_PAGE_DIVISOR;
    uint64 kern_alloc_end;

    if(kern_pages < KERN_MIN_PAGES)
        kern_pages = KERN_MIN_PAGES;
    if(kern_pages >= total_pages)
        kern_pages = total_pages > 1 ? total_pages / 2 : 0;
    kern_alloc_end = alloc_begin + kern_pages * PGSIZE;

    page_ref_init(alloc_begin, alloc_end);
    region_init(&kern_region, "kern_region", alloc_begin, kern_alloc_end);
    region_init(&user_region, "user_region", kern_alloc_end, alloc_end);
    // region_init(&user_region, "user_region", kern_alloc_end, kern_alloc_end + KERN_PAGES * PGSIZE);
}

// 释放物理页
// 失败则panic锁死
void  pmem_free(uint64 page, bool in_kernel)
{
    // 根据in_kernel选择释放到的区域
    alloc_region_t* region = in_kernel ? &kern_region : &user_region;
    int ref_idx;

    // kalloc.c kfree
    // 检查地址合法性: 4096字节对齐，地址在分配区范围内
    if((page % PGSIZE) != 0 || page >= region->end || (uint64)page < region->begin)
        panic("pmem_free: invalid page address");

    ref_idx = page_ref_index(page);

    spinlock_acquire(&region->lock); // 获取内存分配锁
    if(page_refs[ref_idx] == 0) {
        spinlock_release(&region->lock);
        panic("pmem_free: ref underflow");
    }
    page_refs[ref_idx]--;
    if(page_refs[ref_idx] != 0) {
        spinlock_release(&region->lock);
        return;
    }

    // Fill with junk to catch dangling refs. 填充垃圾数据有助于发现悬空指针引用
    memset((void*)page, 1, PGSIZE);

    page_node_t* p = (page_node_t*)page;
    p->next = region->list_head;
    region->list_head = p; // 将该页加入空闲链表
    region->allocable++;
    spinlock_release(&region->lock); // 释放内存分配锁
}

// 返回一个可分配的干净物理页
// 失败则panic锁死
void* pmem_alloc(bool in_kernel)
{
    alloc_region_t* region = in_kernel ? &kern_region : &user_region;

    spinlock_acquire(&region->lock); // 获取内存分配锁
    page_node_t* p = region->list_head; // 从空闲链表中取出第一个空闲页
    if(p) {// 如果有空闲页
        region->list_head = p->next; // 更新空闲链表头指针，指向下一个空闲页
        region->allocable--;
        int ref_idx = page_ref_index((uint64)p);
        if(page_refs[ref_idx] != 0) {
            spinlock_release(&region->lock);
            panic("pmem_alloc: ref leak");
        }
        page_refs[ref_idx] = 1;
    }
    spinlock_release(&region->lock); // 释放内存分配锁
    if(p) // 如果分配成功
        memset((void*)p, 0, PGSIZE); // fill with junk
    else {
        printf("pmem_alloc: %s region out of memory, allocable=%d\n",
               in_kernel ? "kernel" : "user", region->allocable);
        panic("pmem_alloc: out of memory");
    }

    return (void*)p;
}

/**
 * Add a reference to an allocated physical page shared by multiple page tables.
 */
void pmem_ref_page(uint64 page, bool in_kernel)
{
    alloc_region_t* region = in_kernel ? &kern_region : &user_region;
    int ref_idx;

    if((page % PGSIZE) != 0 || page >= region->end || page < region->begin)
        panic("pmem_ref_page: invalid page address");

    ref_idx = page_ref_index(page);

    spinlock_acquire(&region->lock);
    if(page_refs[ref_idx] == 0) {
        spinlock_release(&region->lock);
        panic("pmem_ref_page: unallocated page");
    }
    if(page_refs[ref_idx] == 0xffff) {
        spinlock_release(&region->lock);
        panic("pmem_ref_page: ref overflow");
    }
    page_refs[ref_idx]++;
    spinlock_release(&region->lock);
}

