static uint64 la_shared_execve_from_trapframe(trapframe_t *tf)
{
    proc_t *p = myproc();
    char *path = (char *)kmalloc(DIR_PATH_LEN);
    char *argv[ELF_MAXARGS];
    uint64 uargv, uarg;
    int i;

    if (p == 0 || tf == 0 || path == 0)
        return -1;
    memset(argv, 0, sizeof(argv));

    if (uvm_copyin_str(p->pgtbl, (uint64)path,
                       arch_syscall_tf_arg(tf, 0), DIR_PATH_LEN) < 0)
        goto bad;

    uargv = arch_syscall_tf_arg(tf, 1);
    if (uargv == 0) {
        argv[0] = 0;
    } else {
        for (i = 0; i < ELF_MAXARGS; i++) {
            if (uvm_copyin(p->pgtbl, (uint64)&uarg,
                           uargv + sizeof(uint64) * i, sizeof(uint64)) < 0)
                goto bad;
            if (uarg == 0) {
                argv[i] = 0;
                break;
            }
            argv[i] = (char *)pmem_alloc(false);
            if (argv[i] == 0)
                goto bad;
            if (uvm_copyin_str(p->pgtbl, (uint64)argv[i], uarg, PGSIZE) < 0)
                goto bad;
        }
        if (i == ELF_MAXARGS)
            goto bad;
    }

    int ret = proc_exec(path, argv);
    for (i = 0; i < ELF_MAXARGS && argv[i] != 0; i++)
        pmem_free((uint64)argv[i], false);
    kfree(path);
    if (ret < 0)
        arch_syscall_advance_tf_user_pc(tf);
    return ret;

bad:
    for (i = 0; i < ELF_MAXARGS && argv[i] != 0; i++)
        pmem_free((uint64)argv[i], false);
    if (path != 0)
        kfree(path);
    arch_syscall_advance_tf_user_pc(tf);
    return -1;
}

static int syscall_dispatch_light_number(int num, trapframe_t *tf, uint64 *ret)
{
    int handled = 0;

    if (tf == 0 || ret == 0)
        return 0;

    switch (num) {
    case SYS_exec:
    case SYS_execve:
        *ret = la_shared_execve_from_trapframe(tf);
        return 1;
    case SYS_shutdown:
        arch_syscall_advance_tf_user_pc(tf);
        la_platform_shutdown();
        return 1;
    case SYS_brk:
        *ret = sys_brk();
        arch_syscall_advance_tf_user_pc(tf);
        return 1;
    case SYS_mmap:
        *ret = sys_mmap();
        arch_syscall_advance_tf_user_pc(tf);
        return 1;
    case SYS_mprotect:
        *ret = sys_mprotect();
        arch_syscall_advance_tf_user_pc(tf);
        return 1;
    case SYS_munmap:
        *ret = sys_munmap();
        arch_syscall_advance_tf_user_pc(tf);
        return 1;
    case SYS_fork:
        arch_syscall_advance_tf_user_pc(tf);
        *ret = proc_fork(0);
        return 1;
    case SYS_wait:
        arch_syscall_advance_tf_user_pc(tf);
        {
            int wait_ret = proc_wait(-1, arch_syscall_tf_arg(tf, 0), 0);
            *ret = wait_ret < 0 ? (uint64)-10 : (uint64)wait_ret;
        }
        return 1;
    case SYS_clone:
        arch_syscall_advance_tf_user_pc(tf);
#if defined(__loongarch64)
        *ret = proc_clone(arch_syscall_tf_arg(tf, 0),
                          arch_syscall_tf_arg(tf, 1),
