            int wait_ret = proc_wait((int)arch_syscall_tf_arg(tf, 0),
                                     arch_syscall_tf_arg(tf, 1),
                                     (int)arch_syscall_tf_arg(tf, 2));
            *ret = wait_ret < 0 ? (uint64)-10 : (uint64)wait_ret;
        }
        return 1;
    case SYS_exit:
    case SYS_exit_group:
        proc_exit((int)arch_syscall_tf_arg(tf, 0));
        handled = 1;
        break;
    case SYS_getpid:
    case SYS_getppid:
