/**
 * @file scheduler_core.c
 * @brief Shared scheduler runnable-selection core.
 */

#include "proc/cpu.h"
#include "proc/proc.h"
#include "proc/scheduler_core.h"
#include "proc/table.h"
#include "lib/lock.h"
#include "lib/print.h"

extern void swtch(context_t *old, context_t *new);

void
proc_scheduler_enqueue_prepared(proc_t *p)
{
    if (p == 0)
        panic("proc_scheduler_enqueue_prepared: missing proc");
    if (!spinlock_holding(&p->lk))
        panic("proc_scheduler_enqueue_prepared: lock");
    if (p->state != USED)
        panic("proc_scheduler_enqueue_prepared: state");

    p->state = RUNNABLE;
}

proc_t *
proc_scheduler_pick_runnable_from(cpu_t *c, proc_t *start)
{
    proc_t *p;

    for (p = start; p < proc_table_end(); p++) {
        spinlock_acquire(&p->lk);
        if (p->state == RUNNABLE) {
            p->state = RUNNING;
            proc_set_current(c, p);
            return p;
        }
        spinlock_release(&p->lk);
    }

    return 0;
}

void
proc_scheduler_reset_selected_reserved(proc_t *p)
{
    if (p == 0)
        panic("proc_scheduler_reset_selected_reserved: missing proc");
    if (!spinlock_holding(&p->lk))
        panic("proc_scheduler_reset_selected_reserved: lock");
    if (p->state != RUNNING)
        panic("proc_scheduler_reset_selected_reserved: state");

    p->state = USED;
}

void
proc_scheduler_run_selected(cpu_t *c, proc_t *p)
{
    if (p == 0)
        panic("proc_scheduler_run_selected: missing proc");
    if (!spinlock_holding(&p->lk))
        panic("proc_scheduler_run_selected: lock");
    if (proc_current(c) != p)
        panic("proc_scheduler_run_selected: current");

    swtch(&c->ctx, &p->ctx);
    proc_set_current(c, 0);
    spinlock_release(&p->lk);
}

void
proc_scheduler_return_selected_reserved(cpu_t *c, proc_t *p)
{
    if (c == 0)
        panic("proc_scheduler_return_selected_reserved: missing cpu");
    if (p == 0)
        panic("proc_scheduler_return_selected_reserved: missing proc");
    if (!spinlock_holding(&p->lk))
        panic("proc_scheduler_return_selected_reserved: lock");
    if (proc_current(c) != p)
        panic("proc_scheduler_return_selected_reserved: current");

    proc_scheduler_reset_selected_reserved(p);
    swtch(&p->ctx, &c->ctx);
    panic("proc_scheduler_return_selected_reserved: resumed");
}

proc_t *
proc_scheduler_run_once_from(cpu_t *c, proc_t *start)
{
    proc_t *p = proc_scheduler_pick_runnable_from(c, start);

    if (p == 0)
        return 0;

    proc_scheduler_run_selected(c, p);
    return p;
}

proc_t *
proc_scheduler_run_prepared_once(cpu_t *c, proc_t *p)
{
    proc_t *selected;

    proc_scheduler_enqueue_prepared(p);
    spinlock_release(&p->lk);
    selected = proc_scheduler_run_once_from(c, p);
    if (selected == 0)
        panic("proc_scheduler_run_prepared_once: not selected");
    if (selected != p)
        panic("proc_scheduler_run_prepared_once: wrong proc");
    return selected;
}

/**
 * @file pci.c
 * @brief Narrow LoongArch64 PCI ECAM scanner for early VirtIO block bring-up.
 *
 * QEMU's LoongArch `virt` machine exposes PCI configuration space at physical
 * `0x20000000`. The current LA baseline uses a direct-map window, so config
 * accesses are simple volatile ECAM loads. This code intentionally scans only
 * bus 0 because the contest command's `virtio-blk-pci` device is on the root
 * bus; bridge enumeration belongs in a later general PCI phase.
 */

#include "pci.h"
#include "platform/platform.h"
#include "platform/cpu.h"

#define PCI_VENDOR_ID 0x00U
#define PCI_DEVICE_ID 0x02U
#define PCI_COMMAND 0x04U
#define PCI_HEADER_TYPE 0x0eU
#define PCI_BAR0 0x10U
#define PCI_INVALID_VENDOR 0xffffU
#define PCI_VENDOR_VIRTIO 0x1af4U
#define PCI_DEVICE_VIRTIO_BLK_TRANSITIONAL 0x1001U
#define PCI_DEVICE_VIRTIO_BLK_MODERN 0x1042U
#define PCI_COMMAND_IO 0x1U
#define PCI_COMMAND_MEMORY 0x2U
#define PCI_COMMAND_MASTER 0x4U
#define PCI_BAR_IO_SPACE 0x1U
#define PCI_BAR_MEM_TYPE_MASK 0x6U
#define PCI_BAR_MEM_TYPE_64 0x4U
#define PCI_BAR_MEM_MASK 0xfffffff0U
#define PCI_BAR_SIZE_PROBE 0xffffffffU

static unsigned long la_pci_next_mmio = LA_PCI_MMIO_PHYS;

/**
 * @brief Convert a PCI function and offset to a direct-mapped ECAM address.
 * @param fn PCI bus/device/function tuple.
 * @param offset Byte offset within the 4 KiB function config page.
 * @return Direct-mapped virtual address for the config byte.
 *
 * @note ECAM uses bus:device:function bits at 20:15:12. The helper masks the
 * offset to one 4 KiB config page so callers cannot accidentally walk into the
 * next function by passing a larger offset.
 */
static volatile void *
la_pci_config_addr(la_pci_function_t fn, la_pci_u32 offset)
{
    unsigned long ecam_offset = ((unsigned long)fn.bus << 20) | ((unsigned long)fn.device << 15) | ((unsigned long)fn.function << 12) | (offset & 0xfffU);

    return (volatile void *)(LA_PCI_ECAM + ecam_offset);
}

la_pci_u8
la_pci_read8(la_pci_function_t fn, la_pci_u32 offset)
{
    return *(volatile la_pci_u8 *)la_pci_config_addr(fn, offset);
}

la_pci_u16
la_pci_read16(la_pci_function_t fn, la_pci_u32 offset)
{
    return *(volatile la_pci_u16 *)la_pci_config_addr(fn, offset);
}

la_pci_u32
la_pci_read32(la_pci_function_t fn, la_pci_u32 offset)
{
    return *(volatile la_pci_u32 *)la_pci_config_addr(fn, offset);
}

void la_pci_write16(la_pci_function_t fn, la_pci_u32 offset, la_pci_u16 value)
{
    *(volatile la_pci_u16 *)la_pci_config_addr(fn, offset) = value;
}

void la_pci_write32(la_pci_function_t fn, la_pci_u32 offset, la_pci_u32 value)
{
    *(volatile la_pci_u32 *)la_pci_config_addr(fn, offset) = value;
}

/**
 * @brief Round a BAR size up to the next 4 KiB boundary.
 * @param size Raw BAR size in bytes.
 * @return Page-aligned size suitable for the early MMIO allocator.
 */
static unsigned long
la_pci_align_mmio_size(unsigned long size)
{
    if (size < 0x1000UL)
        size = 0x1000UL;
    return (size + 0xfffUL) & ~0xfffUL;
}

/**
 * @brief Allocate a chunk from the early LA PCI MMIO window.
 * @param size Requested BAR size in bytes.
 * @return Physical PCI MMIO address assigned to the BAR.
 */
static unsigned long
la_pci_alloc_mmio(unsigned long size)
{
    unsigned long base = la_pci_next_mmio;

    la_pci_next_mmio += la_pci_align_mmio_size(size);
    return base;
}

/**
 * @brief Probe a memory BAR size using the standard all-ones mechanism.
 * @param fn PCI function containing the BAR.
 * @param bar BAR index.
 * @param is_64 Receives whether the BAR is a 64-bit memory BAR.
 * @return BAR size in bytes, or 0 when the BAR is unsupported for this helper.
 *
 * @warning The caller must only use this during early single-core device setup.
 * The BAR is temporarily overwritten and immediately restored.
 */
static unsigned long
la_pci_probe_mmio_bar_size(la_pci_function_t fn, la_pci_u8 bar, int *is_64)
{
    la_pci_u32 offset = PCI_BAR0 + (la_pci_u32)bar * 4U;
    la_pci_u32 old_lo = la_pci_read32(fn, offset);
    la_pci_u32 old_hi = 0;
    la_pci_u32 mask_lo;
    la_pci_u32 mask_hi = 0;
    unsigned long size;

    if (bar > 5 || (old_lo & PCI_BAR_IO_SPACE) != 0)
        return 0;

    *is_64 = (old_lo & PCI_BAR_MEM_TYPE_MASK) == PCI_BAR_MEM_TYPE_64;
    if (*is_64 && bar == 5)
        return 0;

    if (*is_64)
    {
        old_hi = la_pci_read32(fn, offset + 4U);
        la_pci_write32(fn, offset + 4U, PCI_BAR_SIZE_PROBE);
    }
    la_pci_write32(fn, offset, PCI_BAR_SIZE_PROBE);
    __sync_synchronize();

    mask_lo = la_pci_read32(fn, offset);
    if (*is_64)
        mask_hi = la_pci_read32(fn, offset + 4U);

    la_pci_write32(fn, offset, old_lo);
    if (*is_64)
        la_pci_write32(fn, offset + 4U, old_hi);
    __sync_synchronize();

    if (*is_64)
    {
        unsigned long mask = ((unsigned long)mask_hi << 32) | (mask_lo & PCI_BAR_MEM_MASK);
        size = (~mask) + 1UL;
    }
    else
    {
        size = (unsigned long)(~(mask_lo & PCI_BAR_MEM_MASK)) + 1UL;
    }

    return size;
}

int la_pci_assign_mmio_bar_if_needed(la_pci_function_t fn, la_pci_u8 bar)
{
    la_pci_u32 offset = PCI_BAR0 + (la_pci_u32)bar * 4U;
    la_pci_u32 raw;
    int is_64 = 0;
    unsigned long size;
    unsigned long base;

    if (bar > 5)
    {
        la_uart_puts("stage: PCI BAR index out of range\n");
        return 0;
    }

    raw = la_pci_read32(fn, offset);
    if ((raw & PCI_BAR_IO_SPACE) != 0)
        return 1;
    if ((raw & PCI_BAR_MEM_MASK) != 0)
        return 1;

