/**
 * Initialize FAT32 filesystem.
 *
 * 1. Initializes buffer cache and node cache.
 * 2. Reads Boot Sector (BPB) to load filesystem geometry.
 * 3. Populates global `fat_info` with layout details (sectors per cluster, root cluster, etc.).
 */
void fat32_init()
{
    // 1. Initialize Buffer Cache
    buf_init();

    // 2. Initialize Node Cache Lock
    fat32_node_init();

    // 3. Read Boot Sector
    buf_t *b = buf_read(0);
    struct fat32_bpb *bpb = (struct fat32_bpb *)b->data;

    // Verify basic FAT32 signature logic if needed,
    // but relies on trusting the img for now or checking bytes_per_sector
    if (bpb->bytes_per_sector != FAT32_SECTOR_SIZE)
    {
        panic("fat32_init: invalid sector size, expected 512");
    }

    // 4. Fill FAT Info
    fat_info.sectors_per_cluster = bpb->sectors_per_cluster;
    fat_info.bytes_per_cluster = bpb->sectors_per_cluster * FAT32_SECTOR_SIZE;
    fat_info.fat_start_sector = bpb->reserved_sectors;
    fat_info.root_cluster = bpb->root_cluster;
    fat_info.sectors_per_fat = bpb->fat_sz_32;
    fat_info.fat_count = bpb->fat_count;

    // Data Start = Reserved + (FATs * FATSize)
    fat_info.first_data_sector = bpb->reserved_sectors +
                                 (bpb->fat_count * bpb->fat_sz_32);

    printf("FAT32 Init:\n");
    printf("  Root Cluster: %d\n", fat_info.root_cluster);
    printf("  Sectors Per Cluster: %d\n", fat_info.sectors_per_cluster);
    printf("  Data Start Sector: %d\n", fat_info.first_data_sector);
    printf("  Sectors Per FAT: %d\n", fat_info.sectors_per_fat);

    buf_release(b);
}

/**
 * Convert cluster number to absolute sector number on disk.
 *
 * @param cluster The cluster index.
 * @return The first sector number of the cluster.
 */
static uint32 cluster_to_sector(uint32 cluster)
{
    if (cluster == 0)
        return 0;
    return fat_info.first_data_sector +
           (cluster - 2) * fat_info.sectors_per_cluster;
}

/**
 * Get the next cluster in the chain from FAT table.
 *
 * @param cluster Current cluster number.
 * @return Next cluster number, or 0 if End of Chain (EOC).
 */
static uint32 next_cluster(uint32 cluster)
{
    uint32 fat_offset = cluster * 4;
    uint32 fat_sector = fat_info.fat_start_sector + (fat_offset / FAT32_SECTOR_SIZE);
    uint32 ent_offset = fat_offset % FAT32_SECTOR_SIZE;

    buf_t *b = buf_read(fat_sector);
    uint32 next = *(uint32 *)(b->data + ent_offset) & 0x0FFFFFFF;
    buf_release(b);

    if (next >= FAT32_EOC)
        return 0; // End of Chain
    return next;
}

/**
 * Allocate a new node from the in-memory cache.
 * Sets ref=1.
 *
 * @return Pointer to new node.
 * @panic If cache is full.
 */
fat32_node *fat32_node_alloc()
{
    spinlock_acquire(&node_cache.lock);
    for (int i = 0; i < N_FAT32_NODE; i++)
    {
        if (!node_cache.nodes[i].valid)
        {
            fat32_node *node = &node_cache.nodes[i];
            node->valid = true;
            node->ref = 1;
            spinlock_release(&node_cache.lock);
            return node;
        }
    }
    spinlock_release(&node_cache.lock);
    panic("fat32_node_alloc: no free nodes");
    return NULL;
}

/**
 * Retrieve a node from cache by its starting cluster (unique ID).
 * If found, increments ref count.
 * If not found, allocates a new slot.
 *
 * @param first_cluster Identifier of the file/dir.
 * @return Pointer to the node.
 */
fat32_node *fat32_node_get(uint32 first_cluster)
{
    spinlock_acquire(&node_cache.lock);
    fat32_node *empty = NULL;

    for (int i = 0; i < N_FAT32_NODE; i++)
    {
        if (node_cache.nodes[i].valid && node_cache.nodes[i].first_cluster == first_cluster)
        {
            node_cache.nodes[i].ref++;
            spinlock_release(&node_cache.lock);
            return &node_cache.nodes[i];
        }
        if (!empty && !node_cache.nodes[i].valid)
        {
            empty = &node_cache.nodes[i];
        }
    }

    if (empty)
    {
        empty->valid = true;
        empty->ref = 1;
        empty->first_cluster = first_cluster;
        empty->attr = 0; // Clear attr for new node allocation
        empty->size = 0;
        spinlock_release(&node_cache.lock);
        return empty;
    }

    spinlock_release(&node_cache.lock);
    panic("fat32_node_get: no free nodes");
    return NULL;
}

/**
 * Increment reference count of a node.
 *
 * @param node Target node.
 */
void fat32_node_dup(fat32_node *node)
{
    spinlock_acquire(&node->lk);
    node->ref++;
    spinlock_release(&node->lk);
}

/**
 * Release reference to a node.
 * Decrements ref count. If 0, invalidates the node (eviction).
 *
 * @param node Target node.
 */
void fat32_node_put(fat32_node *node)
{
    spinlock_acquire(&node_cache.lock);
    spinlock_acquire(&node->lk);

    node->ref--;

    if (node->ref == 0)
    {
        // Simple eviction strategy: invalidate immediately
        // In a real OS, might want to keep LRU
        node->valid = false;
    }

    spinlock_release(&node->lk);
    spinlock_release(&node_cache.lock);
}

