struct pipe* pipealloc(void)
{
    struct pipe* p;
    p = (struct pipe*)pmem_alloc(false);
    if (p == NULL) {
        return NULL;
    }
    spinlock_init(&p->lock, "pipe");
    p->nread = 0;
    p->nwrite = 0;
    p->readopen = 1;
    p->writeopen = 1;
    return p;
}

void pipeclose(struct pipe* p, int writable)
{
    spinlock_acquire(&p->lock);
    if (writable) {
        p->writeopen = 0;
        proc_wakeup(&p->nread);
    } else {
        p->readopen = 0;
        proc_wakeup(&p->nwrite);
    }
    if (p->readopen == 0 && p->writeopen == 0) {
        spinlock_release(&p->lock);
        pmem_free((uint64)p, false);
        return;
    }
    spinlock_release(&p->lock);
}

