{
    int i;
    proc_t* pr = myproc();
    char ch;

    spinlock_acquire(&p->lock);
    while (p->nread == p->nwrite && p->writeopen) {
        // if (myproc()->killed) {
        //     spinlock_release(&p->lock);
        //     return -1;
        // }
        proc_sleep(&p->nread, &p->lock);
    }
    for (i = 0; i < n; i++) {
        if (p->nread == p->nwrite)
