    spinlock_release(&p->lock);
    return i;
}

int pipewrite(struct pipe* p, uint64 addr, int n, bool user_src)
{
    int i;
    proc_t* pr = myproc();
    char ch;

    spinlock_acquire(&p->lock);
    for (i = 0; i < n; i++) {
        while (p->nwrite == p->nread + PIPESIZE) {
            if (p->readopen == 0) { // || myproc()->killed
                spinlock_release(&p->lock);
                return -1;
            }
            proc_wakeup(&p->nread);
            proc_sleep(&p->nwrite, &p->lock);
        }
        if(user_src) {
            if (uvm_copyin(pr->pgtbl, (uint64)&ch, addr + i, 1) == -1)
                break;
        } else {
            ch = ((char*)addr)[i];
        }
        p->data[p->nwrite % PIPESIZE] = ch;
        p->nwrite++;
    }
    proc_wakeup(&p->nread);
    spinlock_release(&p->lock);
    return i;
}

int pipe_poll(struct pipe* p, int want_read, int want_write)
{
    enum {
        POLLIN = 0x001,
        POLLOUT = 0x004,
        POLLHUP = 0x010,
    };
    int revents = 0;

    spinlock_acquire(&p->lock);
    if(want_read && (p->nread != p->nwrite || p->writeopen == 0))
        revents |= POLLIN;
    if(want_write && p->readopen && p->nwrite < p->nread + PIPESIZE)
        revents |= POLLOUT;
    if((want_read && p->writeopen == 0) || (want_write && p->readopen == 0))
        revents |= POLLHUP;
    spinlock_release(&p->lock);

    return revents;
}

int pipe_poll_sleep(struct pipe* p, int want_read, int want_write)
{
    int slept = 0;

    spinlock_acquire(&p->lock);
    if(want_read && p->nread == p->nwrite && p->writeopen) {
        proc_sleep(&p->nread, &p->lock);
        slept = 1;
        spinlock_release(&p->lock);
    } else if(want_write && p->readopen && p->nwrite == p->nread + PIPESIZE) {
        proc_sleep(&p->nwrite, &p->lock);
        slept = 1;
        spinlock_release(&p->lock);
    } else {
        spinlock_release(&p->lock);
    }

    return slept;
}

/**
 * @file vm.c
 * @brief LoongArch64 page-table hooks for shared UVM/proc code.
 */

#include "common.h"
#include "lib/print.h"
#include "lib/str.h"
#include "mem/pmem.h"
#include "mem/vmem.h"
#include "memlayout.h"
#include "platform/csr.h"

static pte_t
la_vm_leaf_pte(uint64 pa, int perm)
{
    pte_t pte = PA_TO_PTE(pa) | LA_PTE_V | LA_PTE_D |
                LA_PTE_MAT_CC | LA_PTE_P;

    if ((perm & PTE_U) != 0)
        pte |= LA_PTE_PLV3;
    if ((perm & PTE_W) != 0)
        pte |= LA_PTE_W;
    if ((perm & PTE_MMAP_SHARED) != 0)
        pte |= PTE_MMAP_SHARED;
    return pte;
}

pte_t *
vm_getpte(pgtbl_t pgtbl, uint64 va, bool alloc)
{
    if (pgtbl == 0)
        return 0;
    if (va >= VA_MAX)
        return 0;

    for (int level = 2; level > 0; level--) {
        pte_t *pte = &pgtbl[VA_TO_VPN(va, level)];

        if ((*pte & PTE_V) != 0) {
            pgtbl = (pgtbl_t)PTE_TO_PA(*pte);
            continue;
        }

        if (!alloc)
            return 0;

        pgtbl = (pgtbl_t)pmem_alloc(true);
        if (pgtbl == 0)
            return 0;
        memset(pgtbl, 0, PGSIZE);
        *pte = PA_TO_PTE((uint64)pgtbl) | PTE_V;
    }

    return &pgtbl[VA_TO_VPN(va, 0)];
}

int32
vm_mappages(pgtbl_t pgtbl, uint64 va, uint64 pa, uint64 len, int perm)
{
    uint64 cur_va;
    uint64 last_va;

    if ((va % PGSIZE) != 0)
        panic("la vm_mappages: va");
    if ((pa % PGSIZE) != 0)
        panic("la vm_mappages: pa");
    if (len == 0)
        panic("la vm_mappages: len");

    cur_va = va;
    last_va = ALIGN_DOWN(va + len - 1, PGSIZE);

    for (;;) {
        pte_t *pte = vm_getpte(pgtbl, cur_va, true);

        if (pte == 0)
            panic("la vm_mappages: pte");
        if ((*pte & PTE_V) != 0 && PTE_TO_PA(*pte) != pa)
            panic("la vm_mappages: remap");

        *pte = la_vm_leaf_pte(pa, perm);

        if (cur_va == last_va)
            break;
        cur_va += PGSIZE;
        pa += PGSIZE;
    }

    la_invalidate_tlb_all();
    return 0;
}

void
vm_unmappages(pgtbl_t pgtbl, uint64 va, uint64 len, bool freeit)
{
    uint64 cur_va;
    uint64 last_va;

    if ((va % PGSIZE) != 0)
        panic("la vm_unmappages: va");
    if (len == 0)
        panic("la vm_unmappages: len");

    cur_va = va;
    last_va = ALIGN_DOWN(va + len - 1, PGSIZE);

    for (;;) {
        pte_t *pte = vm_getpte(pgtbl, cur_va, false);

        if (pte != 0 && (*pte & PTE_V) != 0) {
            if (freeit)
                pmem_free(PTE_TO_PA(*pte), false);
            *pte = 0;
        }

        if (cur_va == last_va)
            break;
        cur_va += PGSIZE;
    }

    la_invalidate_tlb_all();
}

void
vm_print(pgtbl_t pgtbl)
{
    (void)pgtbl;
}

void
kvm_init(void)
{
}

void
kvm_inithart(void)
{
    la_invalidate_tlb_all();
}

