/* ============================================
 * exec 内部文件句柄抽象
 * ============================================
 * 统一 FAT32 和 VFS/EXT4 的文件操作接口，
 * 使 proc_exec() 无需关心底层文件系统类型。
 * ============================================ */

typedef enum {
    EXEC_FILE_NONE = 0,
    EXEC_FILE_FAT32,
    EXEC_FILE_VFS,
    EXEC_FILE_MEMFILE
} exec_file_type_t;

typedef struct {
    exec_file_type_t type;
    union {
        fat32_node *fat32_ep;        /* FAT32 文件系统节点 */
        struct {
            struct vfs_inode *vnode;  /* VFS inode（需在 close 时释放） */
            struct ext4_inode *raw_inode; /* 指向 ext4_inode_private 中的 raw_inode */
        } vfs;
        mem_file_t *memfile;
    };
} exec_file_t;

typedef struct {
    char interp_path[DIR_PATH_LEN];
    char interp_resolved[DIR_PATH_LEN];
    char executed_path[DIR_PATH_LEN];
    char open_path[DIR_PATH_LEN];
    uint64 sp_list[ELF_MAXARGS + 32];
} exec_context_t;

/* ============================================
 * exec_file 操作函数
 * ============================================
 * 对 FAT32 路径：持有 sleeplock 直至 close
 * 对 VFS/EXT4 路径：只读无锁
 * ============================================ */

// 打开可执行文件：先尝试 FAT32，再尝试 VFS/EXT4
// FAT32 路径会在内部获取 sleeplock
// 成功返回 0，失败返回 -1
static int exec_file_open(exec_file_t *ef, const char *path)
{
    const char *resolved = path;
    proc_t *p = myproc();

    if(strcmp(path, "/proc/self/exe") == 0) {
        if(p == NULL || p->exe_path[0] == '\0')
            return -1;
        resolved = p->exe_path;
    }

    if(strcmp(path, "/lib/ld-musl-riscv64-sf.so.1") == 0 ||
       strcmp(path, "/lib/ld-musl-riscv64.so.1") == 0 ||
       strcmp(path, "/lib64/ld-musl-loongarch-lp64d.so.1") == 0 ||
       strcmp(path, "/lib/ld-musl-loongarch-lp64d.so.1") == 0)
        resolved = "/musl/lib/libc.so";
    if(strcmp(path, "/lib/ld-linux-riscv64-lp64d.so.1") == 0)
        resolved = "/glibc/lib/ld-linux-riscv64-lp64d.so.1";
    if(strcmp(path, "/lib64/ld-linux-loongarch-lp64d.so.1") == 0 ||
       strcmp(path, "/lib/ld-linux-loongarch-lp64d.so.1") == 0)
        resolved = "/glibc/lib/ld-linux-loongarch-lp64d.so.1";

    struct path_object_light object;
    char alias_path[DIR_PATH_LEN];
    if(path_object_light_lookup(resolved, &object) &&
       object.backend_path[0] != '\0' &&
       strcmp(object.backend_path, resolved) != 0) {
        strncpy(alias_path, object.backend_path, sizeof(alias_path));
        alias_path[sizeof(alias_path) - 1] = '\0';
        resolved = alias_path;
    }

    mem_file_t *mf = memfile_open(resolved, false);
    if(mf != NULL) {
        ef->type = EXEC_FILE_MEMFILE;
        ef->memfile = mf;
        return 0;
    }

    /* 路径 1: FAT32 */
    fat32_node *fn = fat32_namei((char *)resolved);
    if (fn != NULL) {
        ef->type = EXEC_FILE_FAT32;
        ef->fat32_ep = fn;
        sleeplock_acquire(&fn->slk);
        return 0;
    }

    /* 路径 2: VFS/EXT4 */
    if (vfs_root_sb.s_root != NULL) {
        const char *vfs_path = resolved;
        char *vfs_path_buf = NULL;
        if(resolved[0] != '/') {
            vfs_path_buf = (char *)kmalloc(DIR_PATH_LEN);
            if(vfs_path_buf == NULL)
                return -1;
            if(file_resolve_vfs_path(vfs_path_buf, resolved) < 0) {
                kfree(vfs_path_buf);
                return -1;
            }
            vfs_path = vfs_path_buf;
        }

        struct vfs_inode *vnode = ext4_path_resolve(vfs_path);
        if(vfs_path_buf != NULL)
            kfree(vfs_path_buf);
        if (vnode != NULL) {
            struct ext4_inode_private *priv =
                (struct ext4_inode_private *)vnode->i_private;
            if (priv != NULL) {
                ef->type = EXEC_FILE_VFS;
                ef->vfs.vnode = vnode;
                ef->vfs.raw_inode = &priv->raw_inode;
                return 0;  /* EXT4 只读，无需 sleeplock */
            }
            /* priv 为 NULL，释放 vnode */
            kfree(vnode);
        }
    }

    return -1;
}

// 从可执行文件读取数据
// 返回实际读取的字节数，失败返回 -1
static int exec_file_read(exec_file_t *ef, void *buf, uint32 offset, uint32 size)
{
    if (ef->type == EXEC_FILE_FAT32) {
        return fat32_read(ef->fat32_ep, false, buf, offset, size);
    } else if (ef->type == EXEC_FILE_VFS) {
        return ext4_read_file(ef->vfs.raw_inode, buf, size, offset);
    } else if (ef->type == EXEC_FILE_MEMFILE) {
        return (int)memfile_read(ef->memfile, offset, (uint64)buf, size, false);
    }
    return -1;
}

// 关闭可执行文件，释放资源
// FAT32: 释放 sleeplock + 引用计数
// VFS/EXT4: 释放 vfs_inode 及其私有数据
static void exec_file_close(exec_file_t *ef)
{
    if (ef->type == EXEC_FILE_FAT32) {
        if (ef->fat32_ep != NULL) {
            sleeplock_release(&ef->fat32_ep->slk);
            fat32_node_put(ef->fat32_ep);
        }
    } else if (ef->type == EXEC_FILE_VFS) {
        if (ef->vfs.vnode != NULL) {
            if (ef->vfs.vnode->i_private != NULL)
                kfree(ef->vfs.vnode->i_private);
            kfree(ef->vfs.vnode);
        }
    } else if (ef->type == EXEC_FILE_MEMFILE) {
        if (ef->memfile != NULL)
            memfile_put(ef->memfile);
    }
    ef->type = EXEC_FILE_NONE;
}

/* ============================================
 * ELF 段加载
 * ============================================
 * 对于 ip 管理的 ELF 文件：
 * 将 [offset, offset + size) 的磁盘区域 (一个 segment)
 * 映射到 pgtbl 里的 [va, va + size) 区域
 * 成功返回 0，失败返回 -1
 * ============================================ */
static int load_segment(exec_file_t *ef, uint32 offset, pgtbl_t pgtbl, uint64 va, uint32 size)
{
    /* 支持非页对齐的 ELF 段（如 busybox 的 data 段 va=0x162ff0）
     * 策略：从 va 所在的页边界开始遍历，第一页在页内偏移处写入数据 */
    uint32 page_offset = va % PGSIZE;           /* 段在首页内的偏移 */
    uint64 va_page = ALIGN_DOWN(va, PGSIZE);    /* 首页的页对齐虚拟地址 */

#if EXEC_DEBUG
    printf("[exec] load_segment: offset=0x%x va=0x%p size=0x%x (%d bytes) "
           "page_offset=0x%x va_page=0x%p\n",
           offset, va, size, size, page_offset, va_page);
#endif

    uint32 file_off = offset;
    uint32 remaining = size;
    uint32 write_off = page_offset;  /* 首页写入起始偏移，后续页为 0 */

    for (uint64 cur_va = va_page; remaining > 0; cur_va += PGSIZE) {
        pte_t *pte = vm_getpte(pgtbl, cur_va, false);
        if (pte == NULL || *pte == 0) {
            printf("[exec] load_segment: page not mapped at va=0x%p "
                   "(segment va=0x%p offset=0x%x size=0x%x)\n",
                   cur_va, va, offset, size);
            return -1;
        }
        uint64 pa = PTE_TO_PA(*pte);

        /* 本页可写入的最大字节数（从 write_off 到页末） */
        uint32 chunk = PGSIZE - write_off;
        if (chunk > remaining)
            chunk = remaining;

        int nread = exec_file_read(ef, (void*)(pa + write_off), file_off, chunk);
        if (nread != (int)chunk) {
            printf("[exec] load_segment: read failed at file_offset=0x%x "
                   "pa=0x%p write_off=0x%x expected=%d got=%d\n",
                   file_off, pa, write_off, chunk, nread);
            return -1;
        }

        file_off += chunk;
        remaining -= chunk;
        write_off = 0;  /* 后续页从偏移 0 开始写入 */
    }
    return 0;
}

