extern timer_t sys_timer;

static spinlock_t futex_light_lk;
static int futex_light_lk_ready;

static void
futex_light_lock_init_once(void)
{
    if (futex_light_lk_ready)
        return;
    spinlock_init(&futex_light_lk, "futex-light");
    futex_light_lk_ready = 1;
}

static int
futex_light_copyin(uint64 src, void *dst, uint32 len)
{
    proc_t *p = myproc();

    if (p == 0)
        return -1;
    return uvm_copyin(p->pgtbl, (uint64)dst, src, len);
}

static uint64
futex_light_wait(uint64 uaddr, uint32 val, uint64 timeout_addr, int absolute)
{
    struct timespec timeout;
    uint64 timeout_ticks = 0;
    uint64 ticks0 = 0;
    proc_t *p;
    int cur;

    p = myproc();
    if (proc_signal_has_pending_sigcancel(p)) {
        proc_signal_mark_sigcancel_ready(p);
        return (uint64)-4L;
    }

    if (timeout_addr != 0) {
        if (futex_light_copyin(timeout_addr, &timeout, sizeof(timeout)) < 0)
            return (uint64)-14L;
        if (timeout.tv_nsec >= 1000000000UL)
            return (uint64)-22L;

        if (absolute) {
            uint64 now = arch_time_now();
            uint64 now_sec = now / 10000000UL;
            uint64 now_nsec = (now % 10000000UL) * 100UL;

            if (timeout.tv_sec < now_sec ||
                (timeout.tv_sec == now_sec && timeout.tv_nsec <= now_nsec))
                return (uint64)-110L;
            timeout_ticks = (timeout.tv_sec - now_sec) * 10UL;
            if (timeout.tv_nsec > now_nsec)
                timeout_ticks +=
                    (timeout.tv_nsec - now_nsec + 99999999UL) / 100000000UL;
        } else {
            timeout_ticks = timeout.tv_sec * 10UL +
                            (timeout.tv_nsec + 99999999UL) / 100000000UL;
        }
        if (timeout_ticks == 0)
            timeout_ticks = 1;
    }

    spinlock_acquire(&futex_light_lk);
    if (futex_light_copyin(uaddr, &cur, sizeof(cur)) < 0) {
        spinlock_release(&futex_light_lk);
        return (uint64)-14L;
    }
    if (cur != (int)val) {
        spinlock_release(&futex_light_lk);
        return (uint64)-11L;
    }

    if (timeout_addr != 0) {
        spinlock_release(&futex_light_lk);
        spinlock_acquire(&sys_timer.lk);
        ticks0 = sys_timer.ticks;
        spinlock_release(&sys_timer.lk);
        for (;;) {
            if (proc_signal_has_pending_sigcancel(p)) {
                proc_signal_mark_sigcancel_ready(p);
                return (uint64)-4L;
            }
            if (futex_light_copyin(uaddr, &cur, sizeof(cur)) < 0)
                return (uint64)-14L;
            if (cur != (int)val)
                return 0;
            spinlock_acquire(&sys_timer.lk);
            if (sys_timer.ticks - ticks0 >= timeout_ticks) {
                spinlock_release(&sys_timer.lk);
                return (uint64)-110L;
            }
            spinlock_release(&sys_timer.lk);
            proc_yield();
        }
    }

    proc_sleep((void *)uaddr, &futex_light_lk);
    spinlock_release(&futex_light_lk);
    if (proc_signal_has_pending_sigcancel(p)) {
        proc_signal_mark_sigcancel_ready(p);
        return (uint64)-4L;
    }
    return 0;
}

static uint64
futex_light_wake(uint64 uaddr, uint32 val)
{
    int limit = (int)val;
    int woken;

    if (limit < 0)
        limit = NPROC;
    spinlock_acquire(&futex_light_lk);
    woken = proc_wakeup_limit((void *)uaddr, limit);
    spinlock_release(&futex_light_lk);
    return (uint64)woken;
}

static uint64
futex_light_requeue(uint64 uaddr, uint32 val, uint64 nr_requeue,
                    uint64 uaddr2, uint32 cmp, int compare)
{
    int cur;
    int woken;

    if (uaddr2 == 0)
        return (uint64)-22L;

    spinlock_acquire(&futex_light_lk);
    if (compare) {
        if (futex_light_copyin(uaddr, &cur, sizeof(cur)) < 0) {
            spinlock_release(&futex_light_lk);
            return (uint64)-14L;
        }
        if (cur != (int)cmp) {
            spinlock_release(&futex_light_lk);
            return (uint64)-11L;
        }
    }
    woken = proc_requeue_limit((void *)uaddr, (void *)uaddr2,
                               (int)val, (int)nr_requeue);
    spinlock_release(&futex_light_lk);
    return (uint64)woken;
}

int
syscall_handle_futex_light_trapframe(trapframe_t *tf)
{
    uint64 uaddr;
    uint64 timeout_addr;
    uint64 uaddr2;
    uint32 op_u32;
    uint32 val;
    uint32 cmp;
    int op;
    uint64 ret;

    if (tf == 0)
        return 0;

    uaddr = arch_syscall_tf_arg(tf, 0);
    op_u32 = (uint32)arch_syscall_tf_arg(tf, 1);
    val = (uint32)arch_syscall_tf_arg(tf, 2);
    timeout_addr = arch_syscall_tf_arg(tf, 3);
    op = (int)(op_u32 & 0x7f);
    futex_light_lock_init_once();

    if (uaddr == 0)
        ret = (uint64)-22L;
    else if (op == 0 || op == 9) {
        ret = futex_light_wait(uaddr, val, timeout_addr, op == 9);
    } else if (op == 1 || op == 10) {
        ret = futex_light_wake(uaddr, val);
    } else if (op == 3 || op == 4) {
        uaddr2 = arch_syscall_tf_arg(tf, 4);
        cmp = (uint32)arch_syscall_tf_arg(tf, 5);
        ret = futex_light_requeue(uaddr, val, timeout_addr, uaddr2, cmp,
                                  op == 4);
    } else {
        ret = (uint64)-38L;
    }

    arch_syscall_advance_tf_user_pc(tf);
    arch_syscall_tf_set_return(tf, ret);
    return 1;
}

