/**
 * Resolve the current process umask for newly created volatile files.
 * During early boot (before the first user process exists, e.g. when seeding
 * /etc/passwd) myproc() is NULL; fall back to the Linux default 022.
 */
static uint32 memfile_create_umask()
{
    proc_t *p = myproc();
    if(p == NULL)
        return 022;
    return p->umask & 0777;
}

static uint32 memfile_create_mode(uint32 requested_mode)
{
    return S_IFREG | ((requested_mode & 0777) & ~memfile_create_umask());
}

static int memfile_index_locked(struct mem_file *mf)
{
    if(mf == NULL)
        return MEMFILE_NO_OWNER;
    return (int)(mf - memfiles);
}

static struct mem_file *memfile_owner_locked(struct mem_file *mf)
{
    if(mf == NULL || !mf->used)
        return NULL;
    if(mf->owner_idx >= 0 && mf->owner_idx < MEMFILE_MAX_FILES
       && memfiles[mf->owner_idx].used) {
        return &memfiles[mf->owner_idx];
    }
    return mf;
}

static void memfile_free_pages_from_locked(struct mem_file *mf, int first_page)
{
    if(mf == NULL || mf->owner_idx != MEMFILE_NO_OWNER)
        return;
    if(first_page < 0)
        first_page = 0;
    if(first_page > MEMFILE_MAX_PAGES)
        first_page = MEMFILE_MAX_PAGES;

    for(int i = first_page; i < MEMFILE_MAX_PAGES; i++) {
        if(mf->pages[i] != NULL) {
            pmem_free((uint64)mf->pages[i], true);
            mf->pages[i] = NULL;
        }
    }
}

static void memfile_setup_entry_locked(struct mem_file *mf, uint8 type,
                                       const char *path, uint32 mode)
{
    memset(mf, 0, sizeof(*mf));
    mf->used = true;
    mf->type = type;
    mf->owner_idx = MEMFILE_NO_OWNER;
    mf->nlink = (type == MEMFILE_TYPE_FILE) ? 1 : 0;
    mf->mode = mode;
    strncpy(mf->path, path, DIR_PATH_LEN - 1);
    mf->path[DIR_PATH_LEN - 1] = '\0';
}

void memfile_init()
{
    spinlock_init(&memfile_lk, "memfile");
    memset(memfiles, 0, sizeof(memfiles));
}

static struct mem_file *memfile_find_locked(const char *path)
{
    for(int i = 0; i < MEMFILE_MAX_FILES; i++) {
        if(memfiles[i].used && !memfiles[i].unlinked && strcmp(memfiles[i].path, path) == 0)
            return &memfiles[i];
    }
    return NULL;
}

static void memfile_reclaim_locked(struct mem_file *mf)
{
    if(mf == NULL || !mf->used || !mf->unlinked || mf->ref != 0)
        return;
    if(mf->owner_idx == MEMFILE_NO_OWNER && mf->type == MEMFILE_TYPE_FILE && mf->nlink != 0)
        return;
    memfile_free_pages_from_locked(mf, 0);
    memset(mf, 0, sizeof(*mf));
}

static bool memfile_dir_has_children_locked(const char *path)
{
    int path_len;

    if(path == NULL || path[0] != '/')
        return true;

    path_len = strlen(path);
    for(int i = 0; i < MEMFILE_MAX_FILES; i++) {
        if(!memfiles[i].used || memfiles[i].unlinked)
            continue;
        if(memfiles[i].path[0] == '\0')
            continue;
        if(strcmp(memfiles[i].path, path) == 0)
            continue;
        if(strncmp(memfiles[i].path, path, path_len) == 0
           && memfiles[i].path[path_len] == '/') {
            return true;
        }
    }
    return false;
}

static bool memfile_child_name_locked(const char *dir_path, const char *child_path,
                                      char *name, uint8 *type)
{
    int dir_len;
    const char *tail;
    int name_len = 0;

    if(dir_path == NULL || child_path == NULL || name == NULL || type == NULL)
        return false;
    if(dir_path[0] != '/' || child_path[0] != '/')
        return false;
    if(strcmp(dir_path, child_path) == 0)
        return false;

    dir_len = strlen(dir_path);
    if(strcmp(dir_path, "/") == 0) {
        tail = child_path + 1;
    } else {
        if(strncmp(child_path, dir_path, dir_len) != 0 || child_path[dir_len] != '/')
            return false;
        tail = child_path + dir_len + 1;
    }

    if(tail[0] == '\0')
        return false;
    while(tail[name_len] != '\0' && tail[name_len] != '/')
        name_len++;
    if(name_len == 0 || tail[name_len] != '\0' || name_len >= DIR_PATH_LEN)
        return false;

    for(int i = 0; i < name_len; i++)
        name[i] = tail[i];
    name[name_len] = '\0';
    *type = 8;
    return true;
}

