static void uint_append(char *dst, int *len, int max, uint64 value)
{
    char tmp[24];
    int n = 0;

    if(value == 0) {
        str_append(dst, len, max, "0");
        return;
    }

    while(value != 0 && n < (int)sizeof(tmp)) {
        tmp[n++] = '0' + (value % 10);
        value /= 10;
