}

static int path_is_decimal(const char *s)
{
    if(s == NULL || s[0] == '\0')
        return 0;
    for(int i = 0; s[i] != '\0'; i++) {
        if(s[i] < '0' || s[i] > '9')
            return 0;
    }
    return 1;
}

static int path_parse_pid_component(const char *s)
{
    int pid = 0;

    if(strcmp(s, "self") == 0) {
        proc_t *p = myproc();
        return p ? p->pid : 1;
    }

    if(!path_is_decimal(s))
        return -1;

    for(int i = 0; s[i] != '\0'; i++)
        pid = pid * 10 + (s[i] - '0');
    return pid > 0 ? pid : -1;
}

static int proc_path_kind(const char *path, int want_dir)
{
    if(path == NULL)
        return 0;
    if(strcmp(path, "/proc") == 0)
        return want_dir ? 1 : 0;
    if(strcmp(path, "/proc/meminfo") == 0 ||
       strcmp(path, "/proc/mounts") == 0 ||
       strcmp(path, "/proc/uptime") == 0 ||
       strcmp(path, "/proc/sys/kernel/pid_max") == 0 ||
       strcmp(path, "/proc/sys/kernel/tainted") == 0)
        return want_dir ? 0 : 1;

    if(strncmp(path, "/proc/", 6) == 0) {
        char pidpart[24];
        const char *p = path + 6;
        int i = 0;

        while(p[i] != '\0' && p[i] != '/' && i < (int)sizeof(pidpart) - 1) {
            pidpart[i] = p[i];
            i++;
        }
        pidpart[i] = '\0';
        if(path_parse_pid_component(pidpart) < 0)
            return 0;

        if(p[i] == '\0')
            return want_dir ? 1 : 0;
        if(p[i] != '/')
            return 0;

        const char *tail = p + i + 1;
        if(strcmp(tail, "stat") == 0 ||
           strcmp(tail, "cmdline") == 0 ||
           strcmp(tail, "status") == 0)
            return want_dir ? 0 : 1;
    }

    return 0;
}

