    f->readable = true;
    f->writable = false;
    f->fat32_ep = NULL;
    f->is_vfs = false;
    f->major = DEV_RTC;
    f->open_flags = open_mode;
    f->append = false;
    f->offset = 0;
    strncpy(f->path, path, DIR_PATH_LEN - 1);
    f->path[DIR_PATH_LEN - 1] = '\0';
