    file_t *f = file_alloc();
    if(f == NULL)
        return NULL;

    uint32 acc = open_mode & O_ACCMODE;
    f->type = FD_DEVICE;
    f->readable = (acc == O_RDONLY || acc == O_RDWR);
    f->writable = (acc == O_WRONLY || acc == O_RDWR);
    f->fat32_ep = NULL;
    f->is_vfs = false;
    f->major = DEV_NULL;
    f->open_flags = open_mode;
    f->append = false;
    f->offset = 0;
    strncpy(f->path, path, DIR_PATH_LEN - 1);
    f->path[DIR_PATH_LEN - 1] = '\0';
    return f;
}

