{
    la_uint64 phys;

    if (raw == 0)
        return 0;

    if ((raw & LA_DMW_SEG_MASK) == LA_DMW_SEG_CACHED ||
        (raw & LA_DMW_SEG_MASK) == LA_DMW_SEG_UNCACHED)
    {
        phys = la_mm_direct_to_phys((const void *)raw);
    }
    else
    {
        phys = raw;
    }

    if (!((phys >= LA_LOW_RAM_PHYS_BEGIN && phys < LA_LOW_RAM_PHYS_END) ||
          (phys >= LA_FDT_ROM_PHYS_BEGIN && phys < LA_FDT_ROM_PHYS_END)))
    {
        return 0;
    }

    *direct = (const unsigned char *)la_mm_phys_to_direct(phys);
    return 1;
}

static int
la_fdt_header_is_valid(const unsigned char *blob, la_fdt_header_t *out)
{
    out->magic = la_fdt_be32(blob);
    out->totalsize = la_fdt_be32(blob + 4);
    out->off_dt_struct = la_fdt_be32(blob + 8);
    out->off_dt_strings = la_fdt_be32(blob + 12);
    out->off_mem_rsvmap = la_fdt_be32(blob + 16);
    out->version = la_fdt_be32(blob + 20);
    out->last_comp_version = la_fdt_be32(blob + 24);
    out->boot_cpuid_phys = la_fdt_be32(blob + 28);
    out->size_dt_strings = la_fdt_be32(blob + 32);
    out->size_dt_struct = la_fdt_be32(blob + 36);

    if (out->magic != LA_FDT_MAGIC)
        return 0;
    if (out->totalsize < sizeof(*out) || out->totalsize > LA_FDT_MAX_SIZE)
        return 0;
    if (!la_fdt_range_in_blob(
            out->off_dt_struct,
            out->size_dt_struct,
            out->totalsize))
    {
        return 0;
    }
    if (!la_fdt_range_in_blob(
            out->off_dt_strings,
            out->size_dt_strings,
            out->totalsize))
    {
        return 0;
    }

    return 1;
}

static void
la_mm_add_discovered_region(la_uint64 base, la_uint64 size)
{
    la_uint64 raw_end = base + size;
    la_uint64 page_begin;
    la_uint64 page_end;

    if (size == 0 || raw_end < base)
        return;

    page_begin = (base + (LA_PAGE_SIZE - 1UL)) & LA_PAGE_MASK;
    page_end = raw_end & LA_PAGE_MASK;
    if (page_begin >= page_end)
        return;
    if (la_discovered_region_count >= LA_MM_MAX_DISCOVERED_REGIONS)
        return;

    la_discovered_regions[la_discovered_region_count++] =
        (la_mm_discovered_region_t){
            .phys_begin = page_begin,
            .phys_end = page_end,
            .direct_begin = la_mm_phys_to_direct(page_begin),
            .direct_end = la_mm_phys_to_direct(page_end),
            .flags = LA_MM_DISCOVERED_REGION_CANDIDATE,
            .source = LA_MM_DISCOVERED_REGION_SOURCE_FDT,
            .reject_reason = LA_MM_DISCOVERED_REGION_REJECT_NONE,
        };
}

