/**
 * @brief Write one byte to the LoongArch QEMU UART.
 *
 * The early baseline uses polling against the 16550 line-status register. This
 * keeps the first boot path independent of interrupts and locks.
 *
 * @param ch Character byte to transmit.
 */
void la_uart_putc(int ch)
{
    volatile unsigned char *uart = (volatile unsigned char *)LA_UART0;

    while ((uart[5] & (1U << 5)) == 0)
        ;
    uart[0] = (unsigned char)ch;
}

/**
 * @brief Print a NUL-terminated string on the early serial console.
 *
 * @param s String to print. `\n` is expanded to `\r\n` for serial logs.
 */
void la_uart_puts(const char *s)
{
    while (*s != '\0')
    {
        if (*s == '\n')
            la_uart_putc('\r');
        la_uart_putc(*s++);
    }
}

/**
 * @brief Print a 64-bit value in fixed-width hexadecimal.
 *
 * @param value Value to print.
 */
void la_uart_put_hex(la_platform_uint64 value)
{
    static const char digits[] = "0123456789abcdef";

    for (int shift = 60; shift >= 0; shift -= 4)
        la_uart_putc(digits[(value >> shift) & 0xf]);
}

/**
 * @brief Enter the first LoongArch64 C code path.
 *
 * @param cpu_id Hardware CPU id read from `CSR_CPUID` by the assembly entry.
 * @param boot_arg0 Raw entry argument register 0, preserved before clobbering.
 * @param boot_arg1 Raw entry argument register 1, preserved before clobbering.
 * @param boot_arg2 Raw entry argument register 2, preserved before clobbering.
 *
 * @note The kernel intentionally remains single-core during this milestone.
 * Secondary CPU startup, trap vectors, timer interrupts, and scheduler entry
 * will be added only after the basic LA boot path is reproducible.
 */
void la_boot_main(
    la_platform_uint64 cpu_id,
    la_platform_uint64 boot_arg0,
    la_platform_uint64 boot_arg1,
    la_platform_uint64 boot_arg2)
{
    la_uart_puts("OS-Kernel LoongArch64 baseline boot\n");
    la_uart_puts("stage: entry -> C -> serial output\n");
    la_boot_info_init(cpu_id, boot_arg0, boot_arg1, boot_arg2);
    la_mm_discover_boot_memory_candidates();
    la_mm_validate_boot_memory_candidates();
    la_mm_promote_boot_memory_candidates();
    la_platform_init_cpu(cpu_id);
    if (la_mm_validate_allocator_range() != 0)
    {
        la_uart_puts("panic: LA allocator range escapes low RAM\n");
        la_uart_puts("  low_begin=0x");
        la_uart_put_hex((la_platform_uint64)la_mm_low_ram_begin_direct());
        la_uart_puts(" low_end=0x");
        la_uart_put_hex((la_platform_uint64)la_mm_low_ram_end_direct());
        la_uart_puts("\n  alloc_begin=0x");
        la_uart_put_hex((la_platform_uint64)la_mm_alloc_begin_direct());
        la_uart_puts(" alloc_end=0x");
        la_uart_put_hex((la_platform_uint64)la_mm_alloc_end_direct());
        la_uart_puts("\n");
        for (;;)
            __asm__ volatile("idle 0");
    }
    la_pmem_boot_init_if_enabled();
    mmap_init();
    file_init();
    mount_init();
    light_runtime_install(la_fs_runtime_hooks());

    proc_init();

    la_irq_init();
    la_virtio_pci_block_probe();
    la_boot_enter_shared_scheduler();
    la_platform_shutdown();
}

