/**
 * @file child_lifecycle.c
 * @brief Shared child process lifecycle policy helpers.
 *
 * These helpers keep common child exit and wait-selection semantics out of
 * architecture runtime shims. Callers remain responsible for their own locking
 * model until LA children move from non-runnable bridge slots into the normal
 * scheduler-owned clone/fork path.
 */

#include "lib/print.h"
#include "proc/child_lifecycle.h"
#include "proc/defaults.h"
#include "proc/exit_lifecycle.h"
#include "proc/table.h"

#define PROC_CHILD_SIGNAL_MAX 64UL
#define PROC_CHILD_SIGHUP 1UL
#define PROC_CHILD_SIGINT 2UL
#define PROC_CHILD_SIGKILL 9UL
#define PROC_CHILD_SIGTERM 15UL
#define PROC_CHILD_EINVAL 22L
#define PROC_CHILD_ESRCH 3L
#define PROC_CHILD_REAPED_PID_SLOTS 16UL

static uint64 proc_child_reaped_pids[PROC_CHILD_REAPED_PID_SLOTS];
static unsigned long proc_child_reaped_pid_next;

proc_t *
proc_child_slot_reserve(void)
{
    proc_t *p;

    for (p = proc_table_begin(); p < proc_table_end(); p++) {
        if (p->state == UNUSED) {
            p->state = USED;
            proc_defaults_init(p);
            return p;
        }
    }
    return 0;
}

void
proc_child_slot_release(proc_t *child)
{
    if (child == 0)
        panic("proc child slot release null");
    if (child < proc_table_begin() || child >= proc_table_end())
        panic("proc child slot release slot");
    if (child->state != USED && child->state != ZOMBIE)
        panic("proc child slot release state");

    child->pid = 0;
    proc_defaults_init(child);
    child->state = UNUSED;
}

void
proc_child_bind_identity(proc_t *child, proc_t *parent, int pid)
{
    if (child == 0)
        panic("proc child bind identity null");
    if (child->state != USED)
        panic("proc child bind identity state");

    child->pid = pid;
    child->parent = parent;
    child->exit_state = 0;
    child->killed = 0;
}

void
proc_child_mark_scheduler_prepared(proc_t *child)
{
    if (child == 0)
        panic("proc child scheduler prepared null");
    if (child->state != USED)
        panic("proc child scheduler prepared state");
    if (child->tf == 0 || child->ctx.ra == 0 || child->ctx.sp == 0)
        panic("proc child scheduler prepared metadata");
}

int
proc_child_scheduler_prepared(proc_t *child)
{
    return child != 0 &&
           child->state == USED &&
           child->tf != 0 &&
           child->ctx.ra != 0 &&
           child->ctx.sp != 0;
}

uint64
proc_child_parent_pid(proc_t *child, uint64 fallback)
{
    if (child == 0 || child->parent == 0)
        return fallback;
    return (uint64)child->parent->pid;
}

uint64
proc_child_pid(proc_t *child)
{
    if (child == 0)
        return 0;
    return (uint64)child->pid;
}

void
proc_child_mark_exited(proc_t *child, uint64 exit_code, int killed)
{
    if (child == 0)
        return;

    (void)proc_exit_lifecycle_mark_zombie(child, exit_code, killed);
}

int
proc_child_waitable(proc_t *child, proc_t *parent, uint64 requested_pid)
{
    if (child == 0 || parent == 0)
        return 0;
    if (child->parent != parent)
        return 0;
    if (requested_pid != (uint64)-1L &&
        child->pid != (int)requested_pid)
        return 0;
    return child->state == ZOMBIE;
}

int
proc_child_matches_pid(proc_t *child, uint64 pid)
{
    return child != 0 && child->pid == (int)pid;
}

int
proc_child_owned_by(proc_t *child, proc_t *parent)
{
    return child != 0 && child->parent == parent;
}

int
proc_child_alive(proc_t *child)
{
    return child != 0 && child->state != ZOMBIE;
}

proc_t *
proc_child_find_by_pid(uint64 pid)
{
    proc_t *child;

    for (child = proc_table_begin(); child < proc_table_end(); child++) {
        if (proc_child_matches_pid(child, pid))
            return child;
    }
    return 0;
}

proc_t *
proc_child_find_live_by_pid(uint64 pid)
{
    proc_t *child = proc_child_find_by_pid(pid);

    if (!proc_child_alive(child))
        return 0;
    return child;
}

proc_t *
proc_child_find_waitable(proc_t *parent, uint64 requested_pid)
{
    proc_t *child;

    for (child = proc_table_begin(); child < proc_table_end(); child++) {
        if (proc_child_waitable(child, parent, requested_pid))
            return child;
    }
    return 0;
}

uint64
proc_child_wait_status(proc_t *child)
{
    if (child == 0 || child->state != ZOMBIE)
        panic("proc child wait status");
    return proc_exit_lifecycle_wait_status(child);
}

void
proc_child_remember_reaped_pid(uint64 pid)
{
    if (pid == 0)
        return;

    proc_child_reaped_pids[proc_child_reaped_pid_next] = pid;
    proc_child_reaped_pid_next =
        (proc_child_reaped_pid_next + 1UL) % PROC_CHILD_REAPED_PID_SLOTS;
}

void
proc_child_reaped_pid_reset(void)
{
    for (unsigned long i = 0; i < PROC_CHILD_REAPED_PID_SLOTS; i++)
        proc_child_reaped_pids[i] = 0;
    proc_child_reaped_pid_next = 0;
}

int
proc_child_recently_reaped_pid(uint64 pid)
{
    for (unsigned long i = 0; i < PROC_CHILD_REAPED_PID_SLOTS; i++) {
        if (proc_child_reaped_pids[i] == pid)
            return 1;
    }
    return 0;
}

static int
proc_child_signal_valid(uint64 sig)
{
    return sig <= PROC_CHILD_SIGNAL_MAX;
}

long
proc_child_kill_validate_request(long pid, uint64 sig)
{
    if (pid <= 0 || !proc_child_signal_valid(sig))
        return -PROC_CHILD_EINVAL;
    return 0;
}

long
proc_child_kill_missing_result(int recently_reaped)
{
    return recently_reaped ? 0 : -PROC_CHILD_ESRCH;
}

int
proc_child_kill_is_probe(uint64 sig)
{
    return sig == 0;
}

int
proc_child_signal_terminates(uint64 sig)
{
    return sig == PROC_CHILD_SIGHUP ||
           sig == PROC_CHILD_SIGINT ||
           sig == PROC_CHILD_SIGKILL ||
           sig == PROC_CHILD_SIGTERM;
}

static uint64
proc_child_signal_exit_state(uint64 sig)
{
    return 128UL + (sig & 0xffUL);
}

long
proc_child_kill_apply(proc_t *child, uint64 sig, int *killed)
{
    if (killed != 0)
        *killed = 0;
    if (!proc_child_signal_terminates(sig))
        return -PROC_CHILD_EINVAL;
    if (child != 0 && child->state != ZOMBIE) {
        proc_child_mark_exited(child, proc_child_signal_exit_state(sig), 1);
        if (killed != 0)
            *killed = 1;
    }
    return 0;
}

