// in trap.S
// 内核中断处理流程
extern void kernel_vector();

// 初始化trap中全局共享的东西
void trap_kernel_init()
{
    plic_init();
}

// 各个核心trap初始化
void trap_kernel_inithart()
{
    arch_trap_set_vector((uint64)kernel_vector);
    arch_trap_enable_hart_interrupts();
    plic_inithart();
}

// 外设中断处理 (基于PLIC)
void external_interrupt_handler()
{
    int irq = plic_claim();
    if (irq == UART_IRQ) {
        uart_intr();
    } else if (irq == VIRTIO_IRQ) {
        virtio_disk_intr();
    } else if (irq) {
        printf("unexpected interrupt irq=%d\n", irq);
    }

    if (irq) {
        plic_complete(irq);
    }
}

// 在kernel_vector()里面调用
// 内核态trap处理的核心逻辑
void trap_kernel_handler()
{
    uint64 sepc = arch_trap_saved_pc(); // 记录了发生异常时的pc值
    uint64 sstatus = arch_trap_status(); // 与特权模式和中断相关的状态信息
    uint64 scause = arch_trap_cause(); // 引发trap的原因
    uint64 stval = arch_trap_value(); // 发生trap时保存的附加信息(不同trap不一样)

    // 确认trap来自S-mode且此时trap处于关闭状态
    assert(arch_trap_from_kernel(sstatus),
           "trap_kernel_handler: not from s-mode");
    assert(arch_intr_get() == 0, "trap_kernel_handler: interreput enabled");

    int trap_id = arch_trap_code(scause);

    // 中断异常处理核心逻辑
    if (arch_trap_is_interrupt(scause)) {
        // Interrupt
        switch (trap_id) {
            case 5: // Supervisor timer interrupt
                timer_interrupt_handler();
                if(myproc() != NULL && myproc()->state == RUNNING) {
                    proc_yield();
                }
                break;
            case 1: // Supervisor software interrupt
                printf("SW Interrupt\n");
                arch_trap_clear_software_interrupt();
                break;
            case 9: // Supervisor external interrupt (PLIC)
                external_interrupt_handler();
                break;
            default:
                printf("unknown interrupt: %d\n", trap_id);
                break;
        }
    } else {
        // Exception
        printf("exception: %s\n", exception_info[trap_id]);
        printf("sepc=%p stval=%p\n", sepc, stval);
        panic("trap_kernel_handler: unhandled exception");
    }

    arch_trap_set_saved_pc(sepc);
    arch_trap_set_status(sstatus);
}

/**
 * @file table.c
 * @brief Shared scheduler-visible process table storage.
 */

#include "common.h"
#include "arch/proc.h"
#include "lib/lock.h"
#include "lib/print.h"
#include "memlayout.h"
#include "proc/defaults.h"
#include "proc/proc.h"
#include "proc/table.h"

static proc_t procs[NPROC];

proc_t *
proc_table_begin(void)
{
    return procs;
}

proc_t *
proc_table_end(void)
{
    return &procs[NPROC];
}

int
proc_table_index(proc_t *p)
{
    return (int)(p - procs);
}

void
proc_table_init_slots(void)
{
    proc_t *p;

    for (p = proc_table_begin(); p < proc_table_end(); p++) {
        spinlock_init(&p->lk, "proc_lock");
        p->kstack = arch_proc_kstack_base(proc_table_index(p));
        p->state = UNUSED;
    }
}

proc_t *
proc_table_reserve_locked(void)
{
    proc_t *p;

    for (p = proc_table_begin(); p < proc_table_end(); p++) {
        spinlock_acquire(&p->lk);
        if (p->state == UNUSED) {
            p->state = USED;
            return p;
        }
        spinlock_release(&p->lk);
    }

    return NULL;
}

proc_t *
proc_table_reserve_default_locked(void)
{
    proc_t *p = proc_table_reserve_locked();

    if (p == NULL)
        return NULL;

    proc_defaults_init(p);
    return p;
}

void
proc_table_release_reserved_locked(proc_t *p)
{
    if (p < proc_table_begin() || p >= proc_table_end())
        panic("proc_table_release_reserved_locked: invalid slot");
    if (!spinlock_holding(&p->lk))
        panic("proc_table_release_reserved_locked: lock");
    if (p->state != USED)
        panic("proc_table_release_reserved_locked: state");

    p->state = UNUSED;
    spinlock_release(&p->lk);
}

void
proc_table_release_default_reserved_locked(proc_t *p)
{
    if (p < proc_table_begin() || p >= proc_table_end())
        panic("proc_table_release_default_reserved_locked: invalid slot");
    if (!spinlock_holding(&p->lk))
        panic("proc_table_release_default_reserved_locked: lock");
    if (p->state != USED)
        panic("proc_table_release_default_reserved_locked: state");

    p->pid = 0;
    proc_defaults_init(p);
    p->state = UNUSED;
    spinlock_release(&p->lk);
}

/**
 * @file defaults.c
 * @brief Shared dependency-light process default initialization.
 */

#include "lib/str.h"
#include "proc/defaults.h"
#include "proc/fd_table.h"

static void
proc_defaults_rlimit_init(proc_t *p)
{
    for (int i = 0; i < PROC_RLIMIT_COUNT; i++) {
        p->rlimit_cur[i] = 1024UL * 1024UL * 1024UL;
        p->rlimit_max[i] = 1024UL * 1024UL * 1024UL;
    }
    p->rlimit_cur[PROC_RLIMIT_STACK] = 8UL * 1024UL * 1024UL;
    p->rlimit_max[PROC_RLIMIT_STACK] = 8UL * 1024UL * 1024UL;
    p->rlimit_cur[PROC_RLIMIT_NOFILE] = FILE_PER_PROC;
    p->rlimit_max[PROC_RLIMIT_NOFILE] = FILE_PER_PROC;
}

void
proc_defaults_init(proc_t *p)
{
    p->exit_state = 0;
    p->killed = 0;
    p->gid = 0;
    p->egid = 0;
    p->supp_group_count = 1;
    memset(p->supp_groups, 0, sizeof(p->supp_groups));
    p->pgid = 0;
    p->sid = 0;
    p->umask = 022;
    p->shared_vm = 0;
    p->vm_owner = 0;
    p->sleep_space = 0;
    p->parent = 0;
    p->heap_top = 0;
    p->ustack_pages = 0;
    p->clear_child_tid = 0;
    p->sig_mask = 0;
    memset(p->sig_actions, 0, sizeof(p->sig_actions));
    p->pending_signal = 0;
    p->in_signal = 0;
    p->sig_frame_sp = 0;
    p->sigcancel_ready = 0;
    p->robust_list_head = 0;
    p->robust_list_len = 0;
    p->pthread_base = 0;
    proc_defaults_rlimit_init(p);
    p->mmap = 0;
    p->mmap_alloc = 0;
    p->cwd = 0;
    proc_fd_table_clear(p);
    strncpy(p->cwd_path, "/", DIR_PATH_LEN);
    strncpy(p->exe_path, "/initcode", DIR_PATH_LEN);
}

