/* 
    进程状态集合
    可能的进程状态变换：
    UNUSED -> RUNNABLE 进程初始化
    RUNNABLE -> RUNNING 进程获得CPU使用权
    RUNNING -> RUNNABLE 进程失去CPU使用权
    RUNNING -> SLEEPING 进程睡眠
    SLEEPING -> RUNNABLE 进程苏醒
    RUNNING -> ZOMBIE 进程杀死自己
    RUNNABLE -> ZOMBIE 进程被杀死
    ZOMBIE -> UNUSED 进程被父进程释放回收
*/
enum proc_state {
    UNUSED,       // 未被使用
    USED,         // 已分配但未就绪
    RUNNABLE,     // 准备就绪
    RUNNING,      // 运行中
    SLEEPING,     // 睡眠等待
    ZOMBIE,       // 濒临死亡
};

#define FILE_PER_PROC  128 // 每个进程最多打开的文件数
#define PROC_RLIMIT_COUNT 16
#define PROC_RLIMIT_STACK 3
#define PROC_RLIMIT_NOFILE 7
#define PROC_SUPP_GROUP_MAX 32

// 进程定义
typedef struct proc {

    spinlock_t lk;           // 自旋锁

    /* 下面的字段需要持有锁才能修改 */

    int pid;                 // 标识符
    enum proc_state state;   // 进程状态
    int exit_state;          // 进程退出时的状态(父进程可能关心)
    int killed;              // 被终止信号标记，0 表示未被 kill
    uint32 gid;              /**< Real gid for narrow Linux identity compatibility. */
    uint32 egid;             /**< Effective gid for narrow Linux identity compatibility. */
    uint32 supp_group_count; /**< Supplementary group count for narrow LTP compatibility. */
    uint32 supp_groups[PROC_SUPP_GROUP_MAX]; /**< Process-local supplementary groups. */
    int pgid;                /**< Process group id for narrow LTP process compatibility. */
    int sid;                 /**< Session id for narrow LTP process compatibility. */
    uint32 umask;            /**< Process-local umask state; not yet applied to create modes. */
    int shared_vm;           // clone thread shares user leaf pages
    struct proc* vm_owner;   // CLONE_VM group owner, trapframe mappings stay per proc
    void* sleep_space;       // 睡眠是为在等待什么

    // wait_lock must be held when using this: 不需要持有lock锁
    struct proc* parent;     // 父进程 

    pgtbl_t pgtbl;           // 用户态页表
    void* arch_fd_owner;      // Architecture-owned FD table lifetime handle
    uint64 heap_top;         // 用户堆顶(以字节为单位)
    uint64 ustack_pages;     // 用户栈占用的页面数量
    uint64 clear_child_tid;  // clone child-cleartid futex address
    uint64 sig_mask;         // minimal signal mask for libc sigprocmask/sigsetjmp
    proc_sigaction_t sig_actions[64]; // minimal rt_sigaction table
    uint64 pending_signal;   // pending user handler signals as a bitset
    int in_signal;           // signal handler is active on the user stack
    uint64 sig_frame_sp;     // user signal frame for rt_sigreturn
    uint64 robust_list_head; // Linux robust futex list head for pthread mutexes
    uint64 robust_list_len;
    uint64 rlimit_cur[PROC_RLIMIT_COUNT];
    uint64 rlimit_max[PROC_RLIMIT_COUNT];
    mmap_region_t* mmap;     // 用户可映射区域的起始节点
    trapframe_t* tf;         // 用户态内核态切换时的运行环境暂存空间
    mmap_region_t* mmap_alloc; // 已分配 mmap 区间元数据

    uint64 kstack;           // 内核栈的虚拟地址
    context_t ctx;           // 内核态进程上下文

    fat32_node* cwd;            // 当前目录
    char cwd_path[DIR_PATH_LEN]; // VFS/EXT4 当前目录路径
    char exe_path[DIR_PATH_LEN]; // 当前可执行文件路径，用于 /proc/self/exe
    file_t* filelist[FILE_PER_PROC]; // 打开文件列表
    uint32 fd_flags[FILE_PER_PROC];  // Per-descriptor flags such as FD_CLOEXEC
    int sigcancel_ready;     // pending SIGCANCEL may be delivered at a cancel point
    uint64 pthread_base;     // musl pthread control block base for thread exits
} proc_t;


