/**
 * @file irq.c
 * @brief LoongArch64 external interrupt controller setup and dispatch.
 */

#include "platform/csr.h"
#include "platform/cpu.h"
#include "platform/irq.h"
#include "platform/platform.h"
#include "storage/virtio_pci_block.h"

#define LA_IOCSR_EXTIOI_NODETYPE_BASE 0x14a0U
#define LA_IOCSR_EXTIOI_MAP_BASE 0x14c0U
#define LA_IOCSR_EXTIOI_EN_BASE 0x1600U
#define LA_IOCSR_EXTIOI_ISR_BASE 0x1800U
#define LA_IOCSR_EXTIOI_ROUTE_BASE 0x1c00U

static inline la_uint64
la_iocsr_readq(unsigned int reg)
{
    la_uint64 value;

    __asm__ volatile("iocsrrd.d %0, %1" : "=r"(value) : "r"(reg));
    return value;
}

static inline void
la_iocsr_writeq(la_uint64 value, unsigned int reg)
{
    __asm__ volatile("iocsrwr.d %0, %1" : : "r"(value), "r"(reg) : "memory");
}

static void
la_ls7a_irq_init(void)
{
    la_uint64 pcie_mask = 1UL << LA_PCIE_IRQ;

    *(volatile la_uint64 *)LA_LS7A_INT_MASK_REG = ~pcie_mask;
    *(volatile la_uint64 *)LA_LS7A_INT_EDGE_REG = pcie_mask;
    *(volatile unsigned char *)(LA_LS7A_INT_HTMSI_VEC_REG + LA_PCIE_IRQ) =
        (unsigned char)LA_PCIE_IRQ;
    *(volatile la_uint64 *)LA_LS7A_INT_POL_REG = 0;
    *(volatile la_uint64 *)LA_LS7A_INT_CLEAR_REG = pcie_mask;
}

static void
la_extioi_init(void)
{
    la_uint64 pcie_mask = 1UL << LA_PCIE_IRQ;

    la_iocsr_writeq(pcie_mask, LA_IOCSR_EXTIOI_EN_BASE);
    la_iocsr_writeq(0x01UL, LA_IOCSR_EXTIOI_MAP_BASE);
    la_iocsr_writeq(0x10000UL, LA_IOCSR_EXTIOI_ROUTE_BASE);
    la_iocsr_writeq(0x1UL, LA_IOCSR_EXTIOI_NODETYPE_BASE);
    la_iocsr_writeq(pcie_mask, LA_IOCSR_EXTIOI_ISR_BASE);
}

static la_uint64
la_extioi_claim(void)
{
    return la_iocsr_readq(LA_IOCSR_EXTIOI_ISR_BASE);
}

static void
la_external_complete(la_uint64 irq_mask)
{
    *(volatile la_uint64 *)LA_LS7A_INT_CLEAR_REG = irq_mask;
    la_iocsr_writeq(irq_mask, LA_IOCSR_EXTIOI_ISR_BASE);
}

void
la_irq_init(void)
{
    la_uint64 ecfg = la_read_ecfg();

    la_ls7a_irq_init();
    la_extioi_init();
    la_write_ecfg(ecfg | LA_ECFG_LIE_HWI_MASK);
    la_uart_puts("stage: LA external interrupt controller initialized\n");
}

int
la_irq_handle_external(void)
{
    la_uint64 irq = la_extioi_claim();
    la_uint64 pcie_mask = 1UL << LA_PCIE_IRQ;

    if ((irq & pcie_mask) != 0) {
        la_virtio_pci_interrupt();
        la_external_complete(pcie_mask);
        return 1;
    }

    if (irq != 0) {
        la_uart_puts("stage: LA unexpected external irq mask=0x");
        la_uart_put_hex(irq);
        la_uart_putc('\n');
        la_external_complete(irq);
        return 1;
    }

    return 0;
}

