#ifndef __ARCH_TIME_H__
#define __ARCH_TIME_H__

/**
 * @file time.h
 * @brief Architecture-facing time counter and timer-programming helpers.
 */

#include "common.h"

#if defined(__loongarch64)

#define ARCH_LA_CSR_CRMD  0x0
#define ARCH_LA_CSR_ECFG  0x4
#define ARCH_LA_CSR_CPUID 0x20
#define ARCH_LA_CSR_TCFG  0x41
#define ARCH_LA_CSR_TICLR 0x44
#define ARCH_LA_CRMD_IE   (1UL << 2)
#define ARCH_LA_ECFG_LIE_TI (1UL << 11)
#define ARCH_LA_TCFG_EN   (1UL << 0)
#define ARCH_LA_TCFG_INIT_SHIFT 2
#define ARCH_LA_TICLR_CLR (1UL << 0)

/* LA stable counter read — QEMU `virt` provides a constant-rate timer. */
static inline uint64 arch_time_now(void)
{
    uint64 val;
    uint64 id;

    __asm__ volatile("rdtime.d %0, %1" : "=r"(val), "=r"(id));
    return val;
}

static inline void arch_time_schedule_next(uint64 time)
{
    uint64 now = arch_time_now();
    uint64 delta = time > now ? time - now : 1;
    uint64 tcfg = (delta << ARCH_LA_TCFG_INIT_SHIFT) | ARCH_LA_TCFG_EN;

    __asm__ volatile("csrwr %0, %1" : "+r"(tcfg) : "i"(ARCH_LA_CSR_TCFG) : "memory");
}

static inline void arch_time_enable_supervisor_timer(void)
{
    uint64 ecfg;

    __asm__ volatile("csrrd %0, %1" : "=r"(ecfg) : "i"(ARCH_LA_CSR_ECFG));
    ecfg |= ARCH_LA_ECFG_LIE_TI;
    __asm__ volatile("csrwr %0, %1" : "+r"(ecfg) : "i"(ARCH_LA_CSR_ECFG) : "memory");
}

static inline void arch_time_clear_timer_interrupt(void)
{
    uint64 clear = ARCH_LA_TICLR_CLR;

    __asm__ volatile("csrwr %0, %1" : "+r"(clear) : "i"(ARCH_LA_CSR_TICLR) : "memory");
}

static inline uint64 arch_time_hart_id(void)
{
    uint64 id;
    __asm__ volatile("csrrd %0, %1" : "=r"(id) : "i"(ARCH_LA_CSR_CPUID));
    return id;
}

#else

#include "dev/sbi.h"
#include "riscv.h"

static inline uint64 arch_time_now(void)
{
    return r_time();
}

static inline void arch_time_schedule_next(uint64 time)
{
    sbi_set_timer(time);
}

static inline void arch_time_enable_supervisor_timer(void)
{
    w_sie(r_sie() | SIE_STIE);
}

static inline void arch_time_clear_timer_interrupt(void)
{
}

static inline uint64 arch_time_hart_id(void)
{
    return r_mhartid();
}

static inline void arch_time_set_machine_scratch(uint64 scratch)
{
    w_mscratch(scratch);
}

static inline void arch_time_set_machine_vector(uint64 vector)
{
    w_mtvec(vector);
}

static inline void arch_time_enable_machine_timer_interrupt(void)
{
    w_mie(r_mie() | MIE_MTIE);
}

static inline void arch_time_enable_machine_interrupts(void)
{
    w_mstatus(r_mstatus() | MSTATUS_MIE);
}

#endif

#endif // __ARCH_TIME_H__

/**
 * @file trap.c
 * @brief LoongArch64 trap reporting and shared-process syscall dispatch.
 *
 * LA now treats user traps as architecture-specific entry into the shared
 * process/syscall layer. The old smoke/runtime fallback is intentionally not
 * consulted here; traps that are not owned by the current shared process are
 * reported as architecture faults.
 */

#include "platform/csr.h"
#include "platform/cpu.h"
#include "platform/irq.h"
#include "dev/timer.h"
#include "mem/vmem.h"
#include "proc/cpu.h"
#include "proc/proc.h"
#include "syscall/syscall.h"
#include "trap/proc_return.h"
#include "trap/trap.h"

static int
la_trap_from_user(const struct la_user_smoke_trapframe *tf)
{
    return tf != 0 && ((tf->prmd & LA_PRMD_PPLV) == LA_PRMD_PPLV);
}

static int
la_trap_handle_timer_interrupt(struct la_user_smoke_trapframe *tf)
{
    proc_t *p;

    if (tf == 0 || la_estat_ecode(tf->estat) != LA_ECODE_INTERRUPT ||
        (tf->estat & LA_ESTAT_IS_TI) == 0)
        return 0;

    timer_interrupt_handler();
    p = myproc();
    if (p != 0 && p->tf == tf && la_trap_from_user(tf)) {
        if (p->killed)
            proc_exit(128 + p->killed);
        proc_signal_deliver_pending();
        if (p->shared_vm)
            proc_yield();
    }
    return 1;
}

static int
la_trap_handle_external_interrupt(struct la_user_smoke_trapframe *tf)
{
    if (tf == 0 || la_estat_ecode(tf->estat) != LA_ECODE_INTERRUPT ||
        (tf->estat & la_read_ecfg() & LA_ESTAT_IS_HWI_MASK) == 0)
        return 0;

    return la_irq_handle_external();
}

static int
la_trap_handle_shared_process_syscall(struct la_user_smoke_trapframe *tf)
{
    proc_t *p = myproc();
    uint64 ret;

    if (p == 0 || p->tf != tf || !la_trap_from_user(tf) ||
        la_estat_ecode(tf->estat) != LA_ECODE_SYSCALL)
        return 0;
    if (!syscall_dispatch_number((int)tf->a7, &ret)) {
        la_uart_puts("stage: LA shared syscall unsupported num=0x");
        la_uart_put_hex(tf->a7);
        la_uart_puts("\n");
        return 0;
    }
    p = myproc();
    if (p != 0 && p->tf != tf) {
        if (ret != 0)
            arch_tf_set_return(p->tf, ret);
        if (p->killed)
            proc_exit(128 + p->killed);
        proc_signal_deliver_pending();
        la_proc_user_return(p->tf);
        la_platform_shutdown();
    } else {
        tf->a0 = ret;
        if ((tf->era & LA_DMW_VSEG_9000) == LA_DMW_VSEG_9000) {
            la_uart_puts("stage: LA syscall return invalid user pc\n");
            la_platform_shutdown();
        }
        if (p->killed)
            proc_exit(128 + p->killed);
        proc_signal_deliver_pending();
        la_proc_user_activate_pgtbl(p);
    }
    return 1;
}

static int
la_trap_handle_shared_process_fault(struct la_user_smoke_trapframe *tf)
{
    proc_t *p = myproc();

    if (p == 0 || p->tf != tf || !la_trap_from_user(tf) ||
        la_estat_ecode(tf->estat) == LA_ECODE_SYSCALL ||
        la_estat_ecode(tf->estat) == LA_ECODE_INTERRUPT)
        return 0;
    if (!uvm_mmap_handle_fault(tf->badv))
        proc_exit(128 + la_estat_ecode(tf->estat));
    la_proc_user_activate_pgtbl(p);
    return 1;
}

/**
 * @brief Print a diagnostic report for an unexpected LoongArch exception.
 *
 * @warning This function is for bring-up diagnostics only. Callers that cannot
 * safely return must park the CPU after printing this report.
 */
void la_trap_report(void)
{
    la_uart_puts("panic: LoongArch diagnostic trap\n");
    la_uart_puts("  estat=0x");
    la_uart_put_hex(la_read_estat());
    la_uart_puts("\n  era=0x");
    la_uart_put_hex(la_read_era());
    la_uart_puts("\n  badv=0x");
    la_uart_put_hex(la_read_badv());
    la_uart_puts("\n");
}

/**
 * @brief Handle a returnable LoongArch64 exception.
 *
 * A valid user trap belongs to the current shared `proc_t` and is dispatched
 * through the common syscall table. Anything else is a stale runtime path or a
 * real architecture fault, so keep the diagnostic local and stop instead of
 * re-entering the old LA-only runtime.
 */
void la_trap_handle(struct la_user_smoke_trapframe *tf)
{
    proc_t *p = myproc();

    if (la_trap_handle_external_interrupt(tf))
        return;
    if (la_trap_handle_timer_interrupt(tf))
        return;
    if (la_trap_handle_shared_process_syscall(tf))
        return;
    if (la_trap_handle_shared_process_fault(tf))
        return;

    la_uart_puts("stage: LA trap without shared process owner\n");
    la_uart_puts("  current=0x");
    la_uart_put_hex((uint64)p);
    la_uart_puts("\n  current_tf=0x");
    la_uart_put_hex(p != 0 ? (uint64)p->tf : 0);
    la_uart_puts("\n  tf=0x");
    la_uart_put_hex((uint64)tf);
    la_uart_puts("\n  saved_prmd=0x");
    la_uart_put_hex(tf->prmd);
    la_uart_puts("\n");
    la_uart_puts("  estat=0x");
    la_uart_put_hex(tf->estat);
    la_uart_puts("\n  ecode=0x");
    la_uart_put_hex(la_estat_ecode(tf->estat));
    la_uart_puts("\n  era=0x");
    la_uart_put_hex(tf->era);
    la_uart_puts("\n  badv=0x");
    la_uart_put_hex(tf->badv);
    la_uart_puts("\n  a7=0x");
    la_uart_put_hex(tf->a7);
    la_uart_puts("\n");
    la_platform_shutdown();
}

/**
 * @file proc_return.c
 * @brief LoongArch64 process-facing guarded user-return hook.
 */

#include "platform/cpu.h"
#include "mem/vmem.h"
#include "proc/cpu.h"
#include "trap/proc_return.h"
#include "trap/trapframe_adapter.h"
#include "trap/user_return.h"

extern void la_shared_tlb_refill_entry(void);
extern char la_unowned_trapframe[];

void
la_proc_user_activate_pgtbl(proc_t *p)
{
    la_uint64 root_pa;

    if (p == 0 || p->pgtbl == 0)
    {
        la_uart_puts("la_proc_user_return: missing process page table\n");
        la_platform_shutdown();
    }

    root_pa = (la_uint64)p->pgtbl;
    la_write_dmwin1(LA_DMW_VSEG_9000 | LA_DMW_MAT_CC | LA_DMW_PLV0);
    la_write_tlbrentry((la_uint64)la_shared_tlb_refill_entry);
    la_write_stlbps(0xc);
    la_write_tlbehi(0xc);
    la_write_pwcl(LA_PWCL_VALUE);
    la_write_pwch(LA_PWCH_VALUE);
    la_write_pgdl(root_pa);
    la_invalidate_tlb_all();

}

void
la_proc_user_return(la_trapframe_t *tf)
{
    proc_t *p = myproc();

    if (tf == 0)
    {
        la_uart_puts("la_proc_user_return: missing trapframe\n");
        la_platform_shutdown();
    }
    if (tf == (la_trapframe_t *)la_unowned_trapframe ||
        (tf->era & LA_DMW_VSEG_9000) == LA_DMW_VSEG_9000)
    {
        la_uart_puts("la_proc_user_return: invalid user pc\n");
        la_platform_shutdown();
    }

    la_proc_user_activate_pgtbl(p);
    la_tf_prepare_user_return_state(tf);
    la_tf_enable_user_units();
    la_user_return(tf);
}

/**
 * @file virtio_pci_block.c
 * @brief Public lifecycle for the LoongArch64 VirtIO-PCI block driver.
 *
 * The PCI capability/config logic and queue transfer path live in sibling
 * modules behind `virtio_pci_block_internal.h`. This file owns shared static
 * state, block-device registration, and the boot-time probe sequence.
 */

#include "ext4_probe.h"
#include "virtio_pci_block.h"
#include "virtio_pci_block_internal.h"

unsigned char la_virtio_queue_pages[2 * LA_VIRTIO_PAGE_SIZE]
    __attribute__((aligned(LA_VIRTIO_PAGE_SIZE)));
la_virtio_desc_t *la_vq_desc;
unsigned short *la_vq_avail;
volatile la_virtio_used_ring_t *la_vq_used;
unsigned short la_vq_last_used_idx;
la_virtio_blk_req_t la_sector0_req __attribute__((aligned(16)));
unsigned char la_sector0_data[LA_VIRTIO_SECTOR_SIZE]
    __attribute__((aligned(16)));
unsigned char la_sector0_status __attribute__((aligned(16)));
int la_virtio_queue_failed;
unsigned long la_virtio_request_count;
volatile unsigned int la_virtio_interrupt_count;
volatile unsigned short la_vq_interrupt_used_idx;

static int la_virtio_pci_ready;
static la_virtio_pci_caps_t *la_registered_caps;

static void la_virtio_pci_block_rw(struct buf *buf, bool write);

static const block_device_ops_t la_virtio_pci_block_ops = {
    .rw = la_virtio_pci_block_rw,
};

unsigned long
la_virtio_phys_addr(const void *ptr)
{
    return ((unsigned long)ptr) & ~LA_DMW_MASK;
}

void
la_virtio_memzero(void *ptr, unsigned long len)
{
    unsigned char *p = (unsigned char *)ptr;

    while(len-- != 0)
        *p++ = 0;
}

/**
 * @brief Shared block-device callback for one 512-byte buffer.
 * @param buf Buffer-cache object whose block number selects the disk sector.
 * @param write Non-zero for a write request, zero for a read request.
 *
 * @warning This early callback is registered only after the LA
 * smoke read succeeds. It uses polling completion and therefore must be
 * replaced or wrapped before high-concurrency filesystem workloads.
 */
static void
la_virtio_pci_block_rw(struct buf *buf, bool write)
{
    if(!la_virtio_pci_ready || la_registered_caps == 0){
        la_uart_puts("stage: VirtIO-PCI block request before registration\n");
        return;
    }
    if(!la_virtio_pci_transfer_sector(la_registered_caps, buf->block_num,
                                      buf->data, write)){
        la_uart_puts("stage: VirtIO-PCI block request failed\n");
    }
}

void
la_virtio_pci_block_probe(void)
{
    la_pci_function_t fn;
    la_virtio_pci_caps_t caps;
    static la_virtio_pci_caps_t registered_caps;

    la_virtio_pci_clear_caps(&caps);
    if(!la_pci_find_virtio_block(&fn))
        return;

    if(!la_virtio_pci_parse_caps(fn, &caps))
        return;
    if(!la_virtio_pci_prepare_bars(fn, &caps))
        return;
    la_virtio_pci_clear_caps(&caps);
    if(!la_virtio_pci_parse_caps(fn, &caps))
        return;

    if(!la_virtio_pci_negotiate_features(&caps))
        return;
    if(!la_virtio_pci_setup_queue0(&caps))
        return;
    if(!la_virtio_pci_read_sector0(&caps))
        return;

    registered_caps = caps;
    la_registered_caps = &registered_caps;
    la_virtio_pci_ready = 1;
    block_device_register(&la_virtio_pci_block_ops, "virtio-pci-la");
    la_uart_puts("stage: registered block device ");
    la_uart_puts(block_device_name());
    la_uart_putc('\n');

    la_uart_puts("stage: VirtIO-PCI block device registered for shared use\n");
    la_virtio_pci_print_region("common", &caps.common);
    la_virtio_pci_print_region("notify", &caps.notify);
    la_virtio_pci_print_region("isr", &caps.isr);
    la_virtio_pci_print_region("device", &caps.device);
    la_uart_puts("virtio-pci notify multiplier=");
    la_uart_put_hex(caps.notify.notify_multiplier);
    la_uart_putc('\n');
    la_ext4_probe_root();
}

void
la_virtio_pci_interrupt(void)
{
    if(!la_virtio_pci_ready || la_registered_caps == 0)
        return;

    la_virtio_pci_complete_from_interrupt(la_registered_caps);
}

