    struct vfs_inode *(*lookup)(struct vfs_inode *dir, const char *name);
    int  (*create) (struct vfs_inode *dir, const char *name, uint16 mode);
    int  (*link)   (struct vfs_inode *old_inode, struct vfs_inode *dir, const char *name);
