/* ============================================
 * EXT4 磁盘超级块物理布局（完整版）
 * ============================================
 * 参考仓库：nonix/lwext4_rust/c/lwext4/include/ext4_types.h
 * 原文件名：ext4_types.h (lwext4 库)
 * 开源协议：BSD 2-Clause License
 * Copyright (c) 2013 Grzegorz Kostka (kostka.grzegorz@gmail.com)
 * 
 * 架构映射：lwext4 struct ext4_sblock → 简化后的 struct ext4_super_block
 * 物理布局强约束：此结构体用于直接映射磁盘第0扇区偏移1024字节处的
 * EXT4 超级块，必须强制 __attribute__((packed))，严禁编译器填充对齐。
 * 
 * 修改说明：
 * - 将原简化版扩展为包含 mount/遍历所需的全部关键字段
 * - 保留字段偏移与 Linux ext4 标准完全一致
 * - 添加了 s_first_inode、s_inode_size、s_desc_size 等关键字段
 * ============================================ */

#define EXT4_SUPER_MAGIC       0xEF53
#define EXT4_SUPER_OFFSET      1024  /* 无分区表 EXT4 镜像：superblock 从扇区0偏移1024处开始 */
#define EXT4_MIN_BLOCK_SIZE    1024
#define EXT4_MAX_BLOCK_SIZE    65536
#define EXT4_INODE_SIZE_DEFAULT 128

/* ============================================
 * 完整 EXT4 超级块结构体（1024 字节，含 padding）
 * ============================================ */
struct ext4_super_block {
    /* 0x000 - 基础字段 */
    uint32 s_inodes_count;          /* 0x00: inode 总数 */
    uint32 s_blocks_count_lo;       /* 0x04: 块总数 (低32位) */
    uint32 s_r_blocks_count_lo;     /* 0x08: 保留块数 */
    uint32 s_free_blocks_count_lo;  /* 0x0C: 空闲块数 */
    uint32 s_free_inodes_count;     /* 0x10: 空闲 inode 数 */
    uint32 s_first_data_block;      /* 0x14: 第一个数据块号 */
    uint32 s_log_block_size;        /* 0x18: block_size = 1024 << s_log_block_size */
    uint32 s_log_cluster_size;      /* 0x1C: cluster_size = 1024 << s_log_cluster_size */
    uint32 s_blocks_per_group;      /* 0x20: 每组块数 */
    uint32 s_clusters_per_group;    /* 0x24: 每组 cluster 数 */
    uint32 s_inodes_per_group;      /* 0x28: 每组 inode 数 */
    uint32 s_mtime;                 /* 0x2C: 挂载时间 */
    uint32 s_wtime;                 /* 0x30: 写入时间 */
    uint16 s_mnt_count;             /* 0x34: 挂载计数 */
    uint16 s_max_mnt_count;         /* 0x36: 最大挂载计数 */
    uint16 s_magic;                 /* 0x38: EXT4 Magic Number (0xEF53) */
    uint16 s_state;                 /* 0x3A: 文件系统状态 */
    uint16 s_errors;                /* 0x3C: 错误处理行为 */
    uint16 s_minor_rev_level;       /* 0x3E: 小版本号 */
    uint32 s_lastcheck;             /* 0x40: 最后检查时间 */
    uint32 s_checkinterval;         /* 0x44: 检查间隔 */
    uint32 s_creator_os;            /* 0x48: 创建 OS */
    uint32 s_rev_level;             /* 0x4C: 修订级别 */
    uint16 s_def_resuid;            /* 0x50: 默认保留 uid */
    uint16 s_def_resgid;            /* 0x52: 默认保留 gid */

    /* 0x054 - EXT4_DYNAMIC_REV 字段（rev >= 1） */
    uint32 s_first_inode;           /* 0x54: 第一个非保留 inode (通常是 11) */
    uint16 s_inode_size;            /* 0x58: inode 结构体大小（字节，通常为 128 或 256） */
    uint16 s_block_group_index;     /* 0x5A: 当前超级块所在的块组索引 */
    uint32 s_features_compatible;   /* 0x5C: 兼容特性集 */
    uint32 s_features_incompatible; /* 0x60: 不兼容特性集 */
    uint32 s_features_read_only;    /* 0x64: 只读兼容特性集 */
    uint8  s_uuid[16];              /* 0x68: 128-bit UUID */
    char   s_volume_name[16];       /* 0x78: 卷名 */
    char   s_last_mounted[64];      /* 0x88: 上次挂载目录 */

    /* 0x0C8 - 高级字段 */
    uint32 s_algorithm_usage_bitmap;/* 0xC8: 压缩算法位图 */
    uint8  s_prealloc_blocks;       /* 0xCC */
    uint8  s_prealloc_dir_blocks;   /* 0xCD */
    uint16 s_reserved_gdt_blocks;   /* 0xCE */

    /* 0x0D0 - Journaling 字段 */
    uint8  s_journal_uuid[16];      /* 0xD0 */
    uint32 s_journal_inode_number;  /* 0xE0 */
    uint32 s_journal_dev;           /* 0xE4 */
    uint32 s_last_orphan;           /* 0xE8 */
    uint32 s_hash_seed[4];          /* 0xEC */
    uint8  s_default_hash_version;  /* 0xFC */
    uint8  s_journal_backup_type;
    uint16 s_desc_size;             /* 0xFE: 块组描述符大小（字节，默认 32，64bit 下 64） */

    /* 0x100 - 默认挂载选项 */
    uint32 s_default_mount_opts;
    uint32 s_first_meta_bg;         /* 0x104: 第一个 metablock group */
    uint32 s_mkfs_time;             /* 0x108: 创建时间 */
    uint32 s_journal_blocks[17];    /* 0x10C: journal inode 备份 */

    /* 0x150 - 64-bit 支持 */
    uint32 s_blocks_count_hi;
    uint32 s_r_blocks_count_hi;
    uint32 s_free_blocks_count_hi;
    uint16 s_min_extra_isize;
    uint16 s_want_extra_isize;
    uint32 s_flags;
    uint16 s_raid_stride;
    uint16 s_mmp_interval;
    uint64 s_mmp_block;
    uint32 s_raid_stripe_width;
    uint8  s_log_groups_per_flex;
    uint8  s_checksum_type;
    uint16 s_reserved_pad;
    uint64 s_kbytes_written;

    /* 0x170 - snapshot 相关（通常不需要） */
    uint32 s_snapshot_inum;
    uint32 s_snapshot_id;
    uint64 s_snapshot_r_blocks_count;
    uint32 s_snapshot_list;

    /* 0x184 - 错误计数（通常不需要） */
    uint32 s_error_count;
    uint32 s_first_error_time;
    uint32 s_first_error_ino;
    uint64 s_first_error_block;
    uint8  s_first_error_func[32];
    uint32 s_first_error_line;
    uint32 s_last_error_time;
    uint32 s_last_error_ino;
    uint32 s_last_error_line;
    uint64 s_last_error_block;
    uint8  s_last_error_func[32];
    uint8  s_mount_opts[64];

    /* 0x254 - quota / overhead */
    uint32 s_usr_quota_inum;
    uint32 s_grp_quota_inum;
    uint32 s_overhead_clusters;
    uint32 s_backup_bgs[2];
    uint8  s_encrypt_algos[4];
    uint8  s_encrypt_pw_salt[16];
    uint32 s_lpf_ino;               /* lost+found inode */
    uint32 s_padding[100];          /* padding 到 1024 字节 */
    uint32 s_checksum;              /* crc32c(superblock) */
} __attribute__((packed));

/* ============================================
 * EXT4 块组描述符（完整 64 字节版）
 * ============================================
 * 参考仓库：nonix/lwext4_rust/c/lwext4/include/ext4_types.h
 * 原文件名：ext4_types.h
 * 
 * 修改说明：从 32 字节扩展到 64 字节，支持 64-bit 块地址
 * ============================================ */
struct ext4_group_desc {
    uint32 bg_block_bitmap_lo;      /* 0x00: 块位图块号 */
    uint32 bg_inode_bitmap_lo;      /* 0x04: inode 位图块号 */
    uint32 bg_inode_table_lo;       /* 0x08: inode 表起始块号 */
    uint16 bg_free_blocks_count_lo; /* 0x0C: 空闲块数 */
    uint16 bg_free_inodes_count_lo; /* 0x0E: 空闲 inode 数 */
    uint16 bg_used_dirs_count_lo;   /* 0x10: 目录数 */
    uint16 bg_flags;                /* 0x12: 标志 */
    uint32 bg_exclude_bitmap_lo;    /* 0x14 */
    uint16 bg_block_bitmap_csum_lo; /* 0x18 */
    uint16 bg_inode_bitmap_csum_lo; /* 0x1A */
    uint16 bg_itable_unused_lo;     /* 0x1C */
    uint16 bg_checksum;             /* 0x1E: CRC16 校验 */

    /* 64-bit 扩展字段（rev >= 1 且 64bit feature 启用） */
    uint32 bg_block_bitmap_hi;      /* 0x20 */
    uint32 bg_inode_bitmap_hi;      /* 0x24 */
    uint32 bg_inode_table_hi;       /* 0x28 */
    uint16 bg_free_blocks_count_hi; /* 0x2C */
    uint16 bg_free_inodes_count_hi; /* 0x2E */
    uint16 bg_used_dirs_count_hi;   /* 0x30 */
    uint16 bg_itable_unused_hi;     /* 0x32 */
    uint32 bg_exclude_bitmap_hi;    /* 0x34 */
    uint16 bg_block_bitmap_csum_hi; /* 0x38 */
    uint16 bg_inode_bitmap_csum_hi; /* 0x3A */
    uint32 bg_reserved;             /* 0x3C */
} __attribute__((packed));

